'use client';

import { Heading, Text, Container, Button } from '@/design-system';
import { Warning as WarningIcon } from '@mui/icons-material';
import Link from 'next/link';

export default function ServerErrorPage() {
  return (
    <div
      style={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'var(--background)',
      }}
    >
      <Container maxWidth={600}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '2rem', alignItems: 'center', textAlign: 'center' }}>
          <WarningIcon
            style={{
              fontSize: '120px',
              color: 'var(--destructive)',
            }}
          />
          <Heading
            level={1}
            variant="largeTitle"
          >
            500
          </Heading>
          <Heading
            level={2}
            variant="title2"
            style={{
              color: 'var(--muted-foreground)',
            }}
          >
            Server Error
          </Heading>
          <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
            Something went wrong on our end. We're working to fix it. Please try again later.
          </Text>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem', width: '100%', maxWidth: '300px' }}>
            <Button variant="primary" fullWidth onClick={() => window.location.reload()}>
              Refresh Page
            </Button>
            <Link href="/" style={{ textDecoration: 'none', width: '100%' }}>
              <Button variant="outline" fullWidth>
                Go Home
              </Button>
            </Link>
          </div>
        </div>
      </Container>
    </div>
  );
}

'use client';

import React from 'react';
import { Heading, Text, Container, Card, Button, Badge } from '@/design-system';
import { getMockAppBySubdomain, mockApps } from '@/lib/mock-data/apps';
import { Launch as LaunchIcon, Check as CheckIcon, ArrowBack as ArrowBackIcon, Apps as AppsIcon } from '@mui/icons-material';
import { useParams, useRouter } from 'next/navigation';
import Link from 'next/link';
import {
  Assignment as AssignmentIcon,
  Code as CodeIcon,
  BarChart as BarChartIcon,
  Email as EmailIcon,
  Description as DescriptionIcon,
  CloudQueue as CloudIcon,
} from '@mui/icons-material';

const categoryIcons: Record<string, React.ReactNode> = {
  Productivity: <AssignmentIcon />,
  Development: <CodeIcon />,
  Analytics: <BarChartIcon />,
  Communication: <EmailIcon />,
  Collaboration: <DescriptionIcon />,
  Storage: <CloudIcon />,
};

export default function AppPage() {
  const params = useParams();
  const router = useRouter();
  const subdomain = params.subdomain as string;
  const app = getMockAppBySubdomain(subdomain);

  if (!app) {
    return (
      <Container maxWidth={1200} style={{ padding: '4rem 0', textAlign: 'center' }}>
        <Heading level={1} variant="title1" style={{ marginBottom: '1rem' }}>
          App Not Found
        </Heading>
        <Text variant="body" style={{ color: 'var(--muted-foreground)', marginBottom: '2rem' }}>
          The app you're looking for doesn't exist.
        </Text>
        <Link href="/dashboard/apps" style={{ textDecoration: 'none' }}>
          <Button variant="primary">Back to Marketplace</Button>
        </Link>
      </Container>
    );
  }

  const handleLaunch = () => {
    if (typeof window !== 'undefined') {
      window.open(app.launchUrl, '_blank');
    }
  };

  // Get related apps (same category, excluding current)
  const relatedApps = mockApps.filter(
    (a) => a.category === app.category && a.id !== app.id
  ).slice(0, 3);

  const categoryIcon = categoryIcons[app.category] || <AssignmentIcon />;

  return (
    <div
      style={{
        minHeight: '100vh',
        background: 'var(--background)',
        paddingTop: '2rem',
        paddingBottom: '4rem',
      }}
    >
      <Container maxWidth={1200} style={{ padding: '0 clamp(1rem, 2rem, 2rem)' }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '2rem' }}>
          {/* Back Button */}
          <Link href="/dashboard/apps" style={{ textDecoration: 'none', alignSelf: 'flex-start' }}>
            <Button variant="ghost" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
              <ArrowBackIcon style={{ fontSize: '18px' }} />
              Back to Marketplace
            </Button>
          </Link>

          {/* Hero Section */}
          <Card variant="elevated">
            <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', flexWrap: 'wrap' }}>
                <Badge variant="default" size="sm">{app.category}</Badge>
                <Badge variant="default" size="sm">Available</Badge>
              </div>

              <div style={{ display: 'flex', alignItems: 'center', gap: '1.5rem', flexWrap: 'wrap' }}>
                <div
                  style={{
                    width: '80px',
                    height: '80px',
                    borderRadius: '16px',
                    backgroundColor: 'var(--card)',
                    color: 'var(--muted-foreground)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontSize: '40px',
                    flexShrink: 0,
                  }}
                >
                  {categoryIcon}
                </div>
                <div style={{ flexGrow: 1, minWidth: 0 }}>
                  <Heading
                    level={1}
                    variant="title1"
                    style={{
                      marginBottom: '0.5rem',
                    }}
                  >
                    {app.name}
                  </Heading>
                  {app.tagline && (
                    <Heading
                      level={2}
                      variant="headline"
                      style={{
                        color: 'var(--muted-foreground)',
                      }}
                    >
                      {app.tagline}
                    </Heading>
                  )}
                </div>
              </div>

              <Text
                variant="body"
                style={{
                  color: 'var(--muted-foreground)',
                  maxWidth: '700px',
                  fontSize: '1.125rem',
                  lineHeight: 1.7,
                }}
              >
                {app.longDescription}
              </Text>

              <div style={{ display: 'flex', gap: '1rem', flexWrap: 'wrap', marginTop: '0.5rem' }}>
                <Button
                  variant="primary"
                  size="large"
                  onClick={handleLaunch}
                  style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}
                >
                  <LaunchIcon style={{ fontSize: '18px' }} />
                  Launch App
                </Button>
                <Button
                  variant="outline"
                  size="large"
                  onClick={handleLaunch}
                >
                  Visit {app.subdomain}.platform.com
                </Button>
              </div>
            </div>
          </Card>

          {/* Main Content Grid */}
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
              gap: '1.5rem',
            }}
          >
            {/* Left Column - Features and Use Cases */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
              {/* Features Section */}
              <Card variant="elevated">
                <Heading
                  level={2}
                  variant="headline"
                  style={{
                    marginBottom: '1.5rem',
                  }}
                >
                  Features
                </Heading>
                <div
                  style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                    gap: '1rem',
                  }}
                >
                  {app.features.map((feature, index) => (
                    <div key={index} style={{ display: 'flex', alignItems: 'flex-start', gap: '0.5rem' }}>
                      <CheckIcon
                        style={{
                          color: 'var(--foreground)',
                          marginTop: '2px',
                          fontSize: '20px',
                          flexShrink: 0,
                        }}
                      />
                      <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
                        {feature}
                      </Text>
                    </div>
                  ))}
                </div>
              </Card>

              {/* Use Cases Section */}
              <Card variant="elevated">
                <Heading
                  level={2}
                  variant="headline"
                  style={{
                    marginBottom: '1.5rem',
                  }}
                >
                  Use Cases
                </Heading>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                  {app.useCases.map((useCase, index) => (
                    <div key={index} style={{ display: 'flex', alignItems: 'flex-start', gap: '0.75rem' }}>
                      <div
                        style={{
                          width: '8px',
                          height: '8px',
                          borderRadius: '50%',
                          backgroundColor: 'var(--muted-foreground)',
                          marginTop: '6px',
                          flexShrink: 0,
                        }}
                      />
                      <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
                        {useCase}
                      </Text>
                    </div>
                  ))}
                </div>
              </Card>
            </div>

            {/* Right Column - Quick Info */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
              <Card variant="elevated">
                <Heading
                  level={2}
                  variant="headline"
                  style={{
                    marginBottom: '1rem',
                  }}
                >
                  Quick Information
                </Heading>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                  <div>
                    <Text variant="caption1" style={{ color: 'var(--muted-foreground)', display: 'block', marginBottom: '0.25rem' }}>
                      Category
                    </Text>
                    <Badge variant="default" size="sm">{app.category}</Badge>
                  </div>
                  <div style={{ height: '1px', background: 'var(--border)' }} />
                  <div>
                    <Text variant="caption1" style={{ color: 'var(--muted-foreground)', display: 'block', marginBottom: '0.25rem' }}>
                      Subdomain
                    </Text>
                    <Text
                      variant="body"
                      style={{
                        fontFamily: 'monospace',
                        backgroundColor: 'var(--background)',
                        padding: '0.5rem',
                        borderRadius: '8px',
                        wordBreak: 'break-all',
                      }}
                    >
                      {app.subdomain}
                    </Text>
                  </div>
                  <div style={{ height: '1px', background: 'var(--border)' }} />
                  <div>
                    <Text variant="caption1" style={{ color: 'var(--muted-foreground)', display: 'block', marginBottom: '0.25rem' }}>
                      Status
                    </Text>
                    <Badge variant="default" size="sm">{app.status}</Badge>
                  </div>
                  <div style={{ height: '1px', background: 'var(--border)' }} />
                  <div>
                    <Text variant="caption1" style={{ color: 'var(--muted-foreground)', display: 'block', marginBottom: '0.5rem' }}>
                      Tags
                    </Text>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem' }}>
                      {app.tags.map((tag: any) => (
                        <Badge key={tag} variant="default" size="sm">{tag}</Badge>
                      ))}
                    </div>
                  </div>
                </div>
              </Card>

              <Card variant="elevated">
                <Heading
                  level={2}
                  variant="headline"
                  style={{
                    marginBottom: '1rem',
                  }}
                >
                  Quick Actions
                </Heading>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                  <Button
                    variant="primary"
                    fullWidth
                    onClick={handleLaunch}
                    style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}
                  >
                    <LaunchIcon style={{ fontSize: '18px' }} />
                    Launch App
                  </Button>
                  <Link href="/dashboard/apps" style={{ textDecoration: 'none', width: '100%' }}>
                    <Button variant="outline" fullWidth>
                      Back to Marketplace
                    </Button>
                  </Link>
                </div>
              </Card>
            </div>
          </div>

          {/* Related Apps Section */}
          {relatedApps.length > 0 && (
            <div>
              <Heading
                level={2}
                variant="title2"
                style={{
                  marginBottom: '1.5rem',
                }}
              >
                Related Apps
              </Heading>
              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
                  gap: '1.5rem',
                }}
              >
                {relatedApps.map((relatedApp: any) => {
                  const relatedIcon = categoryIcons[relatedApp.category] || <AppsIcon />;
                  return (
                    <div
                      key={relatedApp.id}
                      className="cursor-pointer transition-transform duration-200 hover:-translate-y-1"
                      onClick={() => router.push(`/apps/${relatedApp.subdomain}`)}
                    >
                      <Card variant="elevated">
                      <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                          <div
                            style={{
                              width: '48px',
                              height: '48px',
                              borderRadius: '12px',
                              backgroundColor: 'var(--card)',
                              color: 'var(--muted-foreground)',
                              display: 'flex',
                              alignItems: 'center',
                              justifyContent: 'center',
                              fontSize: '24px',
                              flexShrink: 0,
                            }}
                          >
                            {relatedIcon}
                          </div>
                          <div style={{ flexGrow: 1, minWidth: 0 }}>
                            <Heading level={3} variant="headline" style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                              {relatedApp.name}
                            </Heading>
                            <Text variant="caption1" style={{ color: 'var(--muted-foreground)' }}>
                              {relatedApp.category}
                            </Text>
                          </div>
                        </div>
                        <Text
                          variant="body"
                          style={{
                            color: 'var(--muted-foreground)',
                            display: '-webkit-box',
                            WebkitLineClamp: 2,
                            WebkitBoxOrient: 'vertical',
                            overflow: 'hidden',
                          }}
                        >
                          {relatedApp.description}
                        </Text>
                        <Link href={`/apps/${relatedApp.subdomain}`} style={{ textDecoration: 'none', width: '100%' }}>
                          <Button variant="outline" size="small" fullWidth>
                            View Details
                          </Button>
                        </Link>
                      </div>
                      </Card>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      </Container>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import { LoadingSpinner } from '@/components/feedback/LoadingSpinner';
import { Container, Card, Heading, Text, Alert, Button } from '@/design-system';
import Link from 'next/link';

/**
 * Client-side auth confirmation handler
 * Handles Supabase email verification and password reset callbacks
 * Supabase uses hash fragments (#access_token=...) which are only available client-side
 */
export default function AuthConfirmPage() {
  const router = useRouter();
  const supabase = createClient();
  const [status, setStatus] = useState<'loading' | 'success' | 'error'>('loading');
  const [message, setMessage] = useState('Processing...');

  useEffect(() => {
    const handleCallback = async () => {
      try {
        // Check URL hash for access_token (Supabase uses hash fragments)
        const hashParams = new URLSearchParams(
          typeof window !== 'undefined' ? window.location.hash.substring(1) : ''
        );
        const accessToken = hashParams.get('access_token');
        const refreshToken = hashParams.get('refresh_token');
        const type = hashParams.get('type');
        const error = hashParams.get('error');
        const errorDescription = hashParams.get('error_description');

        // Handle errors
        if (error) {
          console.error('Auth callback error:', error, errorDescription);
          setStatus('error');
          setMessage(errorDescription || error || 'Authentication failed');
          return;
        }

        // Check query parameters (for OTP-based verification)
        const searchParams = new URLSearchParams(window.location.search);
        const code = searchParams.get('code');
        const tokenHash = searchParams.get('token_hash');
        const queryType = searchParams.get('type');

        // Handle OTP-based verification first (query params)
        if (code && tokenHash) {
          const { error: verifyError } = await supabase.auth.verifyOtp({
            type: (queryType || 'email') as any,
            token_hash: tokenHash,
            token: code,
          } as any);

          if (verifyError) {
            throw verifyError;
          }

          if (queryType === 'email') {
            setStatus('success');
            setMessage('Email verified successfully! Redirecting to login...');
            setTimeout(() => {
              router.push('/login?verified=success');
            }, 2000);
            return;
          } else if (queryType === 'recovery') {
            setStatus('success');
            setMessage('Password reset link verified. Redirecting...');
            setTimeout(() => {
              router.push('/reset-password');
            }, 1000);
            return;
          } else {
            router.push('/dashboard/home');
            return;
          }
        }

        // If we have hash-based tokens, set the session
        if (accessToken && refreshToken) {
          const { data, error: sessionError } = await supabase.auth.setSession({
            access_token: accessToken,
            refresh_token: refreshToken,
          });

          if (sessionError) {
            throw sessionError;
          }

          // Handle different callback types
          if (type === 'email' || queryType === 'email') {
            setStatus('success');
            setMessage('Email verified successfully! Redirecting to login...');
            setTimeout(() => {
              router.push('/login?verified=success');
            }, 2000);
          } else if (type === 'recovery' || queryType === 'recovery') {
            setStatus('success');
            setMessage('Password reset link verified. Redirecting...');
            setTimeout(() => {
              router.push('/reset-password');
            }, 1000);
          } else {
            // Other types - redirect to dashboard
            setStatus('success');
            setMessage('Authentication successful! Redirecting...');
            setTimeout(() => {
              router.push('/dashboard/home');
            }, 1000);
          }
        } else {
          // Check if we already have a session
          const { data: { session } } = await supabase.auth.getSession();
          if (session) {
            setStatus('success');
            setMessage('Already authenticated. Redirecting...');
            setTimeout(() => {
              router.push('/dashboard/home');
            }, 1000);
          } else {
            // No tokens found - might be a direct visit
            setStatus('error');
            setMessage('No authentication tokens found. Please use the link from your email.');
          }
        }
      } catch (err: any) {
        console.error('Auth callback error:', err);
        setStatus('error');
        setMessage(err.message || 'Authentication failed. Please try again.');
      }
    };

    handleCallback();
  }, [router, supabase.auth]);

  return (
    <div
      style={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'var(--background)',
        padding: '1rem',
      }}
    >
      <Container maxWidth={600}>
        <Card variant="elevated" className="w-full max-w-[450px] mx-auto">
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem', alignItems: 'center', textAlign: 'center' }}>
            {status === 'loading' && (
              <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1rem' }}>
                <LoadingSpinner size="medium" />
                <span style={{ color: 'var(--muted-foreground)', fontSize: '0.875rem' }}>{message}</span>
              </div>
            )}

            {status === 'success' && (
              <>
                <Heading level={2} variant="headline">
                  Success!
                </Heading>
                <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
                  {message}
                </Text>
              </>
            )}

            {status === 'error' && (
              <>
                <Heading level={2} variant="headline">
                  Authentication Failed
                </Heading>
                <Alert variant="error" message={message} />
                <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem', width: '100%', marginTop: '1rem' }}>
                  <Link href="/login" style={{ textDecoration: 'none', width: '100%' }}>
                    <Button variant="primary" fullWidth>
                      Go to Login
                    </Button>
                  </Link>
                  <Link href="/forgot-password" style={{ textDecoration: 'none', width: '100%' }}>
                    <Button variant="outline" fullWidth>
                      Reset Password
                    </Button>
                  </Link>
                </div>
              </>
            )}
          </div>
        </Card>
      </Container>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import { Heading, Text, Container, Card, Button, Badge, Alert, Modal } from '@/design-system';
import { designTokens } from '@/lib/theme/tokens';
import {
  CheckCircle as CheckCircleIcon,
  Cancel as CancelIcon,
  Visibility as VisibilityIcon,
  Delete as DeleteIcon,
} from '@mui/icons-material';
import { trpc } from '@/lib/trpc/client';
import { SectionLoader } from '@/components/feedback/SectionLoader';
import { TextField } from '@/components/forms/TextField';
import Link from 'next/link';

type TabType = 'pending' | 'live';

export default function AdminDealsReviewPage() {
  const [activeTab, setActiveTab] = useState<TabType>('pending');
  const [rejectDialogOpen, setRejectDialogOpen] = useState(false);
  const [removeDialogOpen, setRemoveDialogOpen] = useState(false);
  const [selectedDeal, setSelectedDeal] = useState<string | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');

  const { data: pendingDeals, isLoading: isLoadingPending, refetch: refetchPending } = (trpc as any).deal.getPendingReview.useQuery();
  const { data: allDeals, isLoading: isLoadingAll, refetch: refetchAll } = (trpc as any).deal.getAllMarketplace.useQuery(undefined, {
    enabled: activeTab === 'live',
  });

  const approveMutation = (trpc as any).deal.approve.useMutation({
    onSuccess: () => {
      refetchPending();
      refetchAll();
    },
  });

  const rejectMutation = (trpc as any).deal.reject.useMutation({
    onSuccess: () => {
      setRejectDialogOpen(false);
      setRejectionReason('');
      setSelectedDeal(null);
      refetchPending();
      refetchAll();
    },
  });

  const removeMutation = (trpc as any).deal.removeFromMarketplace.useMutation({
    onSuccess: () => {
      setRemoveDialogOpen(false);
      setSelectedDeal(null);
      refetchPending();
      refetchAll();
    },
  });

  const handleApprove = async (dealId: string, makeLive: boolean = false) => {
    try {
      await approveMutation.mutateAsync({ id: dealId, makeLive });
    } catch (error) {
      console.error('Failed to approve:', error);
    }
  };

  const handleReject = async () => {
    if (!selectedDeal || !rejectionReason.trim()) return;
    try {
      await rejectMutation.mutateAsync({ id: selectedDeal, reason: rejectionReason });
    } catch (error) {
      console.error('Failed to reject:', error);
    }
  };

  const handleRemove = async () => {
    if (!selectedDeal) return;
    try {
      await removeMutation.mutateAsync({ dealId: selectedDeal });
    } catch (error) {
      console.error('Failed to remove:', error);
    }
  };

  const isLoading = activeTab === 'pending' ? isLoadingPending : isLoadingAll;
  const liveDeals = allDeals?.filter((deal: any) => deal.status === 'live') || [];

  return (
    <Container 
      maxWidth={1200} 
      style={{ 
        padding: `clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']}) clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']})`,
        width: '100%',
        boxSizing: 'border-box',
      }}
    >
      <Heading level={1} variant="title1" style={{ marginBottom: '2rem' }}>
        Deal Management
      </Heading>

      {/* Tabs */}
      <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '2rem', borderBottom: '2px solid var(--border)' }}>
        <Button
          variant={activeTab === 'pending' ? 'primary' : 'outline'}
          onClick={() => setActiveTab('pending')}
          style={{
            borderRadius: '0',
            borderBottom: activeTab === 'pending' ? `2px solid ${designTokens.colors.primary.main}` : '2px solid transparent',
            marginBottom: '-2px',
          }}
        >
          Pending Review
          {pendingDeals && pendingDeals.length > 0 && (
            <Badge variant="warning" size="sm" className="ml-2">
              {pendingDeals.length}
            </Badge>
          )}
        </Button>
        <Button
          variant={activeTab === 'live' ? 'primary' : 'outline'}
          onClick={() => setActiveTab('live')}
          style={{
            borderRadius: '0',
            borderBottom: activeTab === 'live' ? `2px solid ${designTokens.colors.primary.main}` : '2px solid transparent',
            marginBottom: '-2px',
          }}
        >
          Live Deals
          {liveDeals && liveDeals.length > 0 && (
            <Badge variant="success" size="sm" className="ml-2">
              {liveDeals.length}
            </Badge>
          )}
        </Button>
      </div>

      {approveMutation.isError && (
        <Alert variant="error" message={approveMutation.error?.message || 'Failed to approve deal'} className="mb-6" />
      )}

      {rejectMutation.isError && (
        <Alert variant="error" message={rejectMutation.error?.message || 'Failed to reject deal'} className="mb-6" />
      )}

      {removeMutation.isError && (
        <Alert variant="error" message={removeMutation.error?.message || 'Failed to remove deal'} className="mb-6" />
      )}

      {isLoading ? (
        <SectionLoader />
      ) : activeTab === 'pending' ? (
        !pendingDeals || pendingDeals.length === 0 ? (
        <Card variant="elevated" className="p-8 text-center">
          <Heading level={2} variant="headline" style={{ color: 'var(--muted-foreground)', marginBottom: '0.5rem' }}>
            No deals pending review
          </Heading>
          <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
            All submitted deals have been reviewed
          </Text>
        </Card>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
          {pendingDeals.map((deal: any) => {
            const price = typeof deal.price === 'string' ? parseFloat(deal.price) : deal.price;
            return (
              <Card key={deal.id} variant="elevated">
                <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <div style={{ flex: 1 }}>
                      <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center', marginBottom: '0.5rem', flexWrap: 'wrap' }}>
                        <Heading level={3} variant="headline">
                          {deal.title}
                        </Heading>
                        <Badge variant="warning" size="sm">Pending Review</Badge>
                      </div>
                      <Text variant="body" style={{ color: 'var(--muted-foreground)', marginBottom: '0.5rem' }}>
                        ${price.toFixed(2)} • Submitted{' '}
                        {deal.submitted_at
                          ? new Date(deal.submitted_at).toLocaleDateString('en-US', {
                              year: 'numeric',
                              month: 'long',
                              day: 'numeric',
                            })
                          : 'N/A'}
                      </Text>
                      {deal.description && (
                        <Text variant="body" style={{ marginBottom: '1rem', color: 'var(--muted-foreground)' }}>
                          {deal.description.substring(0, 200)}
                          {deal.description.length > 200 ? '...' : ''}
                        </Text>
                      )}
                      <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
                        {deal.category && (
                          <Badge variant="default" size="sm">{deal.category}</Badge>
                        )}
                        {deal.deal_type && (
                          <Badge variant="default" size="sm">
                            {deal.deal_type === 'lifetime' ? 'Lifetime Deal' : deal.deal_type}
                          </Badge>
                        )}
                      </div>
                    </div>
                    <div style={{ display: 'flex', gap: '0.5rem' }}>
                      <Link
                        href={`/marketplace/${deal.id}`}
                        target="_blank"
                        style={{ textDecoration: 'none' }}
                      >
                        <Button variant="outline" size="small">
                          <VisibilityIcon style={{ fontSize: '18px', display: 'flex' }} />
                          View
                        </Button>
                      </Link>
                    </div>
                  </div>

                  <div style={{ paddingTop: '1rem', borderTop: '1px solid var(--border)' }}>
                    <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end', flexWrap: 'wrap' }}>
                      <Button
                        variant="destructive"
                        onClick={() => {
                          setSelectedDeal(deal.id);
                          setRejectDialogOpen(true);
                        }}
                        loading={approveMutation.isLoading || rejectMutation.isLoading}
                        disabled={approveMutation.isLoading || rejectMutation.isLoading}
                      >
                        <CancelIcon style={{ fontSize: '18px', display: 'flex' }} />
                        Reject
                      </Button>
                      <Button
                        variant="secondary"
                        onClick={() => handleApprove(deal.id, false)}
                        loading={approveMutation.isLoading || rejectMutation.isLoading}
                        disabled={approveMutation.isLoading || rejectMutation.isLoading}
                      >
                        <CheckCircleIcon style={{ fontSize: '18px', display: 'flex' }} />
                        Approve
                      </Button>
                      <Button
                        variant="primary"
                        onClick={() => handleApprove(deal.id, true)}
                        loading={approveMutation.isLoading || rejectMutation.isLoading}
                        disabled={approveMutation.isLoading || rejectMutation.isLoading}
                      >
                        <CheckCircleIcon style={{ fontSize: '18px', display: 'flex' }} />
                        Approve & Make Live
                      </Button>
                    </div>
                  </div>
                </div>
              </Card>
            );
          })}
        </div>
      )
      ) : (
        !liveDeals || liveDeals.length === 0 ? (
          <Card variant="elevated" className="p-8 text-center">
            <Heading level={2} variant="headline" style={{ color: 'var(--muted-foreground)', marginBottom: '0.5rem' }}>
              No live deals
            </Heading>
            <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
              There are no deals currently live on the marketplace
            </Text>
          </Card>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
            {liveDeals.map((deal: any) => {
              const price = typeof deal.price === 'string' ? parseFloat(deal.price) : deal.price;
              return (
                <Card key={deal.id} variant="elevated">
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                      <div style={{ flex: 1 }}>
                        <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center', marginBottom: '0.5rem', flexWrap: 'wrap' }}>
                          <Heading level={3} variant="headline">
                            {deal.title}
                          </Heading>
                          <Badge variant="success" size="sm">Live</Badge>
                        </div>
                        <Text variant="body" style={{ color: 'var(--muted-foreground)', marginBottom: '0.5rem' }}>
                          ${price.toFixed(2)} • Live since{' '}
                          {deal.approved_at
                            ? new Date(deal.approved_at).toLocaleDateString('en-US', {
                                year: 'numeric',
                                month: 'long',
                                day: 'numeric',
                              })
                            : 'N/A'}
                        </Text>
                        {deal.description && (
                          <Text variant="body" style={{ marginBottom: '1rem', color: 'var(--muted-foreground)' }}>
                            {deal.description.substring(0, 200)}
                            {deal.description.length > 200 ? '...' : ''}
                          </Text>
                        )}
                        <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
                          {deal.category && (
                            <Badge variant="default" size="sm">{deal.category}</Badge>
                          )}
                          {deal.deal_type && (
                            <Badge variant="default" size="sm">
                              {deal.deal_type === 'lifetime' ? 'Lifetime Deal' : deal.deal_type}
                            </Badge>
                          )}
                        </div>
                      </div>
                      <div style={{ display: 'flex', gap: '0.5rem' }}>
                        <Link
                          href={`/marketplace/${deal.id}`}
                          target="_blank"
                          style={{ textDecoration: 'none' }}
                        >
                          <Button variant="outline" size="small">
                            <VisibilityIcon style={{ fontSize: '18px', display: 'flex' }} />
                            View
                          </Button>
                        </Link>
                      </div>
                    </div>

                    <div style={{ paddingTop: '1rem', borderTop: '1px solid var(--border)' }}>
                      <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end', flexWrap: 'wrap' }}>
                        <Button
                          variant="destructive"
                          onClick={() => {
                            setSelectedDeal(deal.id);
                            setRemoveDialogOpen(true);
                          }}
                          loading={removeMutation.isLoading}
                          disabled={removeMutation.isLoading}
                        >
                          <DeleteIcon style={{ fontSize: '18px', display: 'flex' }} />
                          Remove from Marketplace
                        </Button>
                      </div>
                    </div>
                  </div>
                </Card>
              );
            })}
          </div>
        )
      )}

      {/* Reject Dialog */}
      <Modal
        open={rejectDialogOpen}
        onClose={() => setRejectDialogOpen(false)}
        title="Reject Deal"
      >
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
          <Alert variant="warning" message="This will reject the deal and notify the seller. They can re-submit after making changes." />
          <TextField
            label="Rejection Reason"
            fullWidth
            multiline
            rows={4}
            value={rejectionReason}
            onChange={(e) => setRejectionReason(e.target.value)}
            placeholder="Please provide a reason for rejection (e.g., 'Price exceeds $89 limit', 'Missing required information', etc.)"
            required
          />
          <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end' }}>
            <Button variant="outline" onClick={() => setRejectDialogOpen(false)}>
              Cancel
            </Button>
            <Button
              onClick={handleReject}
              variant="destructive"
              loading={rejectMutation.isLoading}
              disabled={!rejectionReason.trim() || rejectMutation.isLoading}
            >
              {rejectMutation.isLoading ? 'Rejecting...' : 'Reject Deal'}
            </Button>
          </div>
        </div>
      </Modal>

      {/* Remove Dialog */}
      <Modal
        open={removeDialogOpen}
        onClose={() => setRemoveDialogOpen(false)}
        title="Remove Deal from Marketplace"
      >
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
          <Alert variant="warning" message="This will pause the deal and remove it from the public marketplace. The seller will still be able to see it in their dashboard, but it will no longer be visible to buyers." />
          <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
            Are you sure you want to remove this deal from the marketplace? This action can be reversed by the seller or by approving the deal again.
          </Text>
          <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end' }}>
            <Button variant="outline" onClick={() => setRemoveDialogOpen(false)}>
              Cancel
            </Button>
            <Button
              onClick={handleRemove}
              variant="destructive"
              loading={removeMutation.isLoading}
              disabled={removeMutation.isLoading}
            >
              {removeMutation.isLoading ? 'Removing...' : 'Remove from Marketplace'}
            </Button>
          </div>
        </div>
      </Modal>
    </Container>
  );
}

'use client';

import React, { useState } from 'react';
import { Heading, Text, Container, Card, Button, Badge, Alert, Modal } from '@/design-system';
import { designTokens } from '@/lib/theme/tokens';
import {
  PersonAdd as PersonAddIcon,
  PersonRemove as PersonRemoveIcon,
  Shield as ShieldIcon,
  ShieldOutlined as ShieldOutlinedIcon,
} from '@mui/icons-material';
import { trpc } from '@/lib/trpc/client';
import { SectionLoader } from '@/components/feedback/SectionLoader';
import { useAuth } from '@/contexts/AuthContext';

export default function ManageMembersPage() {
  const { user } = useAuth();
  const [selectedUser, setSelectedUser] = useState<{ id: string; email: string; action: string } | null>(null);
  const [confirmDialogOpen, setConfirmDialogOpen] = useState(false);

  const { data: users, isLoading, refetch } = (trpc as any).admin.getAllUsers.useQuery();
  const { data: currentUserRoles } = (trpc as any).user.roles.useQuery();
  const isSuperAdmin = currentUserRoles?.includes('super_admin') || false;

  const promoteToAdminMutation = (trpc as any).admin.promoteToAdmin.useMutation({
    onSuccess: () => {
      setConfirmDialogOpen(false);
      setSelectedUser(null);
      refetch();
    },
  });

  const removeAdminMutation = (trpc as any).admin.removeAdminRole.useMutation({
    onSuccess: () => {
      setConfirmDialogOpen(false);
      setSelectedUser(null);
      refetch();
    },
  });

  const assignSuperAdminMutation = (trpc as any).admin.assignSuperAdmin.useMutation({
    onSuccess: () => {
      setConfirmDialogOpen(false);
      setSelectedUser(null);
      refetch();
    },
  });

  const removeSuperAdminMutation = (trpc as any).admin.removeSuperAdmin.useMutation({
    onSuccess: () => {
      setConfirmDialogOpen(false);
      setSelectedUser(null);
      refetch();
    },
  });

  const handleAction = (userId: string, userEmail: string, action: string) => {
    setSelectedUser({ id: userId, email: userEmail, action });
    setConfirmDialogOpen(true);
  };

  const confirmAction = async () => {
    if (!selectedUser) return;

    try {
      switch (selectedUser.action) {
        case 'promote-admin':
          await promoteToAdminMutation.mutateAsync({ userId: selectedUser.id });
          break;
        case 'remove-admin':
          await removeAdminMutation.mutateAsync({ userId: selectedUser.id });
          break;
        case 'assign-super-admin':
          await assignSuperAdminMutation.mutateAsync({ userId: selectedUser.id });
          break;
        case 'remove-super-admin':
          await removeSuperAdminMutation.mutateAsync({ userId: selectedUser.id });
          break;
      }
    } catch (error) {
      console.error('Action failed:', error);
    }
  };

  const getActionLabel = (action: string) => {
    switch (action) {
      case 'promote-admin':
        return 'Promote to Admin';
      case 'remove-admin':
        return 'Remove Admin Role';
      case 'assign-super-admin':
        return 'Assign Super Admin';
      case 'remove-super-admin':
        return 'Remove Super Admin';
      default:
        return '';
    }
  };

  const getActionMessage = (action: string, email: string) => {
    switch (action) {
      case 'promote-admin':
        return `Are you sure you want to promote ${email} to admin? They will be able to review deals and manage members.`;
      case 'remove-admin':
        return `Are you sure you want to remove admin role from ${email}? They will lose admin privileges.`;
      case 'assign-super-admin':
        return `Are you sure you want to assign super admin role to ${email}? They will have full platform control including the ability to remove admin roles.`;
      case 'remove-super-admin':
        return `Are you sure you want to remove super admin role from ${email}? They will lose super admin privileges.`;
      default:
        return '';
    }
  };

  if (isLoading) {
    return <SectionLoader />;
  }

  return (
    <Container 
      maxWidth={1200} 
      style={{ 
        padding: `clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']}) clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']})`,
        width: '100%',
        boxSizing: 'border-box',
      }}
    >
      <Heading level={1} variant="title1" style={{ marginBottom: '2rem' }}>
        Manage Members
      </Heading>

      {promoteToAdminMutation.isError && (
        <Alert variant="error" message={promoteToAdminMutation.error?.message || 'Failed to promote user'} className="mb-6" />
      )}
      {removeAdminMutation.isError && (
        <Alert variant="error" message={removeAdminMutation.error?.message || 'Failed to remove admin role'} className="mb-6" />
      )}
      {assignSuperAdminMutation.isError && (
        <Alert variant="error" message={assignSuperAdminMutation.error?.message || 'Failed to assign super admin'} className="mb-6" />
      )}
      {removeSuperAdminMutation.isError && (
        <Alert variant="error" message={removeSuperAdminMutation.error?.message || 'Failed to remove super admin'} className="mb-6" />
      )}

      {!users || users.length === 0 ? (
        <Card variant="elevated" className="p-8 text-center">
          <Heading level={2} variant="headline" style={{ color: 'var(--muted-foreground)', marginBottom: '0.5rem' }}>
            No members found
          </Heading>
          <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
            There are no users in the system yet.
          </Text>
        </Card>
      ) : (
        <Card variant="elevated">
          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr style={{ borderBottom: '1px solid var(--border)' }}>
                  <th style={{ textAlign: 'left', padding: '1rem', fontWeight: 600 }}>Email</th>
                  <th style={{ textAlign: 'left', padding: '1rem', fontWeight: 600 }}>Name</th>
                  <th style={{ textAlign: 'left', padding: '1rem', fontWeight: 600 }}>Roles</th>
                  <th style={{ textAlign: 'left', padding: '1rem', fontWeight: 600 }}>Created</th>
                  <th style={{ textAlign: 'right', padding: '1rem', fontWeight: 600 }}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {users.map((userItem: any) => {
                  const hasAdmin = userItem.roles.includes('admin');
                  const hasSuperAdmin = userItem.roles.includes('super_admin');
                  const isCurrentUser = user?.id === userItem.id;

                  return (
                    <tr key={userItem.id} style={{ borderBottom: '1px solid var(--border)' }}>
                      <td style={{ padding: '1rem' }}>
                        <Text variant="body">{userItem.email}</Text>
                      </td>
                      <td style={{ padding: '1rem' }}>
                        <Text variant="body">{userItem.name || '—'}</Text>
                      </td>
                      <td style={{ padding: '1rem' }}>
                        <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
                          {userItem.roles.length === 0 ? (
                            <Badge variant="default" size="sm">user</Badge>
                          ) : (
                            userItem.roles.map((role: any) => (
                              <Badge 
                                key={role} 
                                variant={role === 'super_admin' ? 'error' : role === 'admin' ? 'warning' : 'default'} 
                                size="sm"
                              >
                                {role}
                              </Badge>
                            ))
                          )}
                        </div>
                      </td>
                      <td style={{ padding: '1rem' }}>
                        <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
                          {userItem.created_at
                            ? new Date(userItem.created_at).toLocaleDateString('en-US', {
                                year: 'numeric',
                                month: 'short',
                                day: 'numeric',
                              })
                            : '—'}
                        </Text>
                      </td>
                      <td style={{ padding: '1rem', textAlign: 'right' }}>
                        <div style={{ display: 'flex', gap: '0.5rem', justifyContent: 'flex-end', flexWrap: 'wrap' }}>
                          {!hasAdmin && (
                            <Button
                              variant="outline"
                              size="small"
                              onClick={() => handleAction(userItem.id, userItem.email, 'promote-admin')}
                              loading={promoteToAdminMutation.isLoading}
                              disabled={promoteToAdminMutation.isLoading}
                            >
                              <PersonAddIcon style={{ fontSize: '18px' }} />
                              Promote to Admin
                            </Button>
                          )}
                          {hasAdmin && isSuperAdmin && !isCurrentUser && (
                            <Button
                              variant="outline"
                              size="small"
                              onClick={() => handleAction(userItem.id, userItem.email, 'remove-admin')}
                              loading={removeAdminMutation.isLoading}
                              disabled={removeAdminMutation.isLoading || hasSuperAdmin}
                            >
                              <PersonRemoveIcon style={{ fontSize: '18px' }} />
                              Remove Admin
                            </Button>
                          )}
                          {!hasSuperAdmin && isSuperAdmin && (
                            <Button
                              variant="primary"
                              size="small"
                              onClick={() => handleAction(userItem.id, userItem.email, 'assign-super-admin')}
                              loading={assignSuperAdminMutation.isLoading}
                              disabled={assignSuperAdminMutation.isLoading}
                            >
                              <ShieldIcon style={{ fontSize: '18px' }} />
                              Assign Super Admin
                            </Button>
                          )}
                          {hasSuperAdmin && isSuperAdmin && !isCurrentUser && (
                            <Button
                              variant="destructive"
                              size="small"
                              onClick={() => handleAction(userItem.id, userItem.email, 'remove-super-admin')}
                              loading={removeSuperAdminMutation.isLoading}
                              disabled={removeSuperAdminMutation.isLoading}
                            >
                              <ShieldOutlinedIcon style={{ fontSize: '18px' }} />
                              Remove Super Admin
                            </Button>
                          )}
                          {isCurrentUser && (
                            <Text variant="caption1" style={{ color: 'var(--muted-foreground)', fontStyle: 'italic' }}>
                              (You)
                            </Text>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </Card>
      )}

      {/* Confirmation Modal */}
      <Modal
        open={confirmDialogOpen}
        onClose={() => {
          setConfirmDialogOpen(false);
          setSelectedUser(null);
        }}
        title={selectedUser ? getActionLabel(selectedUser.action) : 'Confirm Action'}
      >
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
          {selectedUser && (
            <>
              <Alert 
                variant={selectedUser.action.includes('remove') ? 'warning' : 'info'} 
                message={getActionMessage(selectedUser.action, selectedUser.email)} 
              />
              <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end' }}>
                <Button 
                  variant="outline" 
                  onClick={() => {
                    setConfirmDialogOpen(false);
                    setSelectedUser(null);
                  }}
                >
                  Cancel
                </Button>
                <Button
                  variant={selectedUser.action.includes('remove') ? 'destructive' : 'primary'}
                  onClick={confirmAction}
                  loading={
                    promoteToAdminMutation.isLoading ||
                    removeAdminMutation.isLoading ||
                    assignSuperAdminMutation.isLoading ||
                    removeSuperAdminMutation.isLoading
                  }
                  disabled={
                    promoteToAdminMutation.isLoading ||
                    removeAdminMutation.isLoading ||
                    assignSuperAdminMutation.isLoading ||
                    removeSuperAdminMutation.isLoading
                  }
                >
                  Confirm
                </Button>
              </div>
            </>
          )}
        </div>
      </Modal>
    </Container>
  );
}

'use client';

import React from 'react';
import { Heading, Text, Container, Card, Button } from '@/design-system';
import { designTokens } from '@/lib/theme/tokens';
import {
  CheckCircle as CheckCircleIcon,
  People as PeopleIcon,
  ArrowForward as ArrowForwardIcon,
} from '@mui/icons-material';
import { useRouter } from 'next/navigation';

interface AdminCardProps {
  icon: React.ReactNode;
  title: string;
  description: string;
  buttonText: string;
  href: string;
}

function AdminCard({ icon, title, description, buttonText, href }: AdminCardProps) {
  const router = useRouter();

  return (
    <div
      onClick={() => router.push(href)}
      className="cursor-pointer transition-all duration-200"
    >
      <Card variant="elevated">
      <div style={{ 
        display: 'flex', 
        flexDirection: 'column', 
        height: '100%',
        gap: '1rem',
        alignItems: 'flex-start',
      }}>
        {/* Icon */}
        <div style={{ 
          width: '64px', 
          height: '64px', 
          borderRadius: '12px', 
          backgroundColor: 'rgba(60,131,245,0.12)', 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'center',
          flexShrink: 0,
        }}>
          {icon}
        </div>

        {/* Title */}
        <Heading level={2} variant="headline" style={{ margin: 0 }}>
          {title}
        </Heading>

        {/* Description - flex: 1 to push button to bottom */}
        <Text 
          variant="body" 
          style={{ 
            color: 'var(--muted-foreground)',
            flex: 1,
            margin: 0,
          }}
        >
          {description}
        </Text>

        {/* Button - aligned at bottom */}
        <Button 
          variant="primary" 
          style={{ 
            marginTop: 'auto',
            display: 'flex',
            alignItems: 'center',
            gap: '0.5rem',
          }}
          onClick={(e) => {
            e.stopPropagation();
            router.push(href);
          }}
        >
          {buttonText}
          <ArrowForwardIcon style={{ fontSize: '16px' }} />
        </Button>
      </div>
      </Card>
    </div>
  );
}

