'use client';

import React, { useState, useEffect } from 'react';
import { useRouter, useParams } from 'next/navigation';
import { trpc } from '@/lib/trpc/client';
import { Heading, Text, Container, Card, Button, Alert } from '@/design-system';
import { LoadingSpinner } from '@/components/feedback/LoadingSpinner';
import { designTokens } from '@/lib/theme/tokens';
import { TextField } from '@/components/forms/TextField';
import { ArrowBack as ArrowBackIcon } from '@mui/icons-material';
import Link from 'next/link';

export default function EditAppPage() {
  const router = useRouter();
  const params = useParams();
  const appId = params.id as string;

  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [errors, setErrors] = useState<{ name?: string }>({});

  const { data: app, isLoading, error } = (trpc as any).app.get.useQuery(
    { id: appId },
    { enabled: !!appId }
  );

  const updateApp = (trpc as any).app.update.useMutation({
    onSuccess: () => {
      router.push('/dashboard/apps');
    },
  });

  // Populate form when app data loads
  useEffect(() => {
    if (app) {
      setName(app.name || '');
      setDescription(app.description || '');
    }
  }, [app]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Validate
    const nameError = !name ? 'App name is required' : undefined;

    if (nameError) {
      setErrors({ name: nameError });
      return;
    }

    setErrors({});

    updateApp.mutate({
      id: appId,
      name,
      description: description || undefined,
    });
  };

  if (isLoading) {
    return (
      <Container 
        maxWidth={600} 
        style={{ 
          padding: `clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']}) clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']})`,
          width: '100%',
          boxSizing: 'border-box',
        }}
      >
        <div
          style={{
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            minHeight: '400px',
          }}
        >
          <LoadingSpinner size="medium" />
        </div>
      </Container>
    );
  }

  if (error || !app) {
    return (
      <Container 
        maxWidth={600} 
        style={{ 
          padding: `clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']}) clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']})`,
          width: '100%',
          boxSizing: 'border-box',
        }}
      >
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
          <Link href="/dashboard/apps" style={{ textDecoration: 'none', alignSelf: 'flex-start' }}>
            <Button variant="ghost" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
              <ArrowBackIcon style={{ fontSize: '18px' }} />
              Back to Apps
            </Button>
          </Link>
          <Alert variant="error" message={error?.message || 'App not found'} />
        </div>
      </Container>
    );
  }

  return (
    <Container 
      maxWidth={600} 
      style={{ 
        padding: `clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']}) clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']})`,
        width: '100%',
        boxSizing: 'border-box',
      }}
    >
      <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
        {/* Back Button */}
        <Link href="/dashboard/apps" style={{ textDecoration: 'none', alignSelf: 'flex-start' }}>
          <Button variant="ghost" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
            <ArrowBackIcon style={{ fontSize: '18px' }} />
            Back to Apps
          </Button>
        </Link>

        {/* Form Card */}
        <Card variant="elevated">
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
            <div>
              <Heading
                level={1}
                variant="title1"
                style={{
                  marginBottom: '0.5rem',
                }}
              >
                Edit App
              </Heading>
              <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
                Update your application details
              </Text>
            </div>

            <form onSubmit={handleSubmit}>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                {/* Error Alert */}
                {updateApp.isError && (
                  <Alert variant="error" message={updateApp.error?.message || 'Failed to update app. Please try again.'} />
                )}

                {/* Name Field */}
                <TextField
                  label="App Name"
                  value={name}
                  onChange={(e) => {
                    setName(e.target.value);
                    if (errors.name) {
                      setErrors({ ...errors, name: undefined });
                    }
                  }}
                  error={!!errors.name}
                  helperText={errors.name}
                  required
                  fullWidth
                  autoFocus
                />

                {/* Subdomain Field (Read-only) */}
                <TextField
                  label="Subdomain"
                  value={app.subdomain || ''}
                  disabled
                  fullWidth
                  helperText="Subdomain cannot be changed after creation"
                />

                {/* Description Field */}
                <TextField
                  label="Description"
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  multiline
                  rows={4}
                  fullWidth
                  placeholder="Description of your app"
                />

                {/* Submit Button */}
                <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end', marginTop: '0.5rem' }}>
                  <Link href="/dashboard/apps" style={{ textDecoration: 'none' }}>
                    <Button
                      variant="outline"
                      disabled={updateApp.isPending}
                    >
                      Cancel
                    </Button>
                  </Link>
                  <Button
                    type="submit"
                    variant="primary"
                    loading={updateApp.isPending}
                    disabled={updateApp.isPending}
                  >
                    {updateApp.isPending ? 'Updating...' : 'Update App'}
                  </Button>
                </div>
              </div>
            </form>
          </div>
        </Card>
      </div>
    </Container>
  );
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { trpc } from '@/lib/trpc/client';
import { Heading, Text, Container, Card, Button, Alert } from '@/design-system';
import { designTokens } from '@/lib/theme/tokens';
import { TextField } from '@/components/forms/TextField';
import { ArrowBack as ArrowBackIcon } from '@mui/icons-material';
import Link from 'next/link';

export default function NewAppPage() {
  const router = useRouter();
  const [name, setName] = useState('');
  const [subdomain, setSubdomain] = useState('');
  const [description, setDescription] = useState('');
  const [errors, setErrors] = useState<{ name?: string; subdomain?: string }>({});

  const createApp = (trpc as any).app.create.useMutation({
    onSuccess: () => {
      router.push('/dashboard/apps');
    },
  });

  const validateSubdomain = (value: string): string | undefined => {
    if (!value) {
      return 'Subdomain is required';
    }
    if (!/^[a-z0-9-]+$/.test(value)) {
      return 'Subdomain can only contain lowercase letters, numbers, and hyphens';
    }
    if (value.length < 1) {
      return 'Subdomain must be at least 1 character';
    }
    if (value.startsWith('-') || value.endsWith('-')) {
      return 'Subdomain cannot start or end with a hyphen';
    }
    return undefined;
  };

  const handleSubdomainChange = (value: string) => {
    const lowerValue = value.toLowerCase().replace(/[^a-z0-9-]/g, '');
    setSubdomain(lowerValue);
    if (errors.subdomain) {
      setErrors({ ...errors, subdomain: validateSubdomain(lowerValue) });
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Validate
    const nameError = !name ? 'App name is required' : undefined;
    const subdomainError = validateSubdomain(subdomain);

    if (nameError || subdomainError) {
      setErrors({ name: nameError, subdomain: subdomainError });
      return;
    }

    setErrors({});

    createApp.mutate({
      name,
      subdomain,
      description: description || undefined,
    });
  };

  return (
    <Container 
      maxWidth={600} 
      style={{ 
        padding: `clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']}) clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']})`,
        width: '100%',
        boxSizing: 'border-box',
      }}
    >
      <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
        {/* Back Button */}
        <Link href="/dashboard/apps" style={{ textDecoration: 'none', alignSelf: 'flex-start' }}>
          <Button variant="ghost" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
            <ArrowBackIcon style={{ fontSize: '18px' }} />
            Back to Apps
          </Button>
        </Link>

        {/* Form Card */}
        <Card variant="elevated">
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
            <div>
              <Heading
                level={1}
                variant="title1"
                style={{
                  marginBottom: '0.5rem',
                }}
              >
                Create New App
              </Heading>
              <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
                Create a new application with a unique subdomain
              </Text>
            </div>

            <form onSubmit={handleSubmit}>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                {/* Error Alert */}
                {createApp.isError && (
                  <Alert variant="error" message={createApp.error?.message || 'Failed to create app. Please try again.'} />
                )}

                {/* Name Field */}
                <TextField
                  label="App Name"
                  value={name}
                  onChange={(e) => {
                    setName(e.target.value);
                    if (errors.name) {
                      setErrors({ ...errors, name: undefined });
                    }
                  }}
                  error={!!errors.name}
                  helperText={errors.name}
                  required
                  fullWidth
                  autoFocus
                />

                {/* Subdomain Field */}
                <TextField
                  label="Subdomain"
                  value={subdomain}
                  onChange={(e) => handleSubdomainChange(e.target.value)}
                  error={!!errors.subdomain}
                  helperText={
                    errors.subdomain ||
                    'Lowercase letters, numbers, and hyphens only. This will be used as your app URL.'
                  }
                  required
                  fullWidth
                  inputProps={{
                    pattern: '[a-z0-9-]+',
                  }}
                />

                {/* Description Field */}
                <TextField
                  label="Description"
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  multiline
                  rows={4}
                  fullWidth
                  placeholder="Optional description of your app"
                />

                {/* Submit Button */}
                <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end', marginTop: '0.5rem' }}>
                  <Link href="/dashboard/apps" style={{ textDecoration: 'none' }}>
                    <Button
                      variant="outline"
                      disabled={createApp.isPending}
                    >
                      Cancel
                    </Button>
                  </Link>
                  <Button
                    type="submit"
                    variant="primary"
                    loading={createApp.isPending}
                    disabled={createApp.isPending}
                  >
                    {createApp.isPending ? 'Creating...' : 'Create App'}
                  </Button>
                </div>
              </div>
            </form>
          </div>
        </Card>

        {/* Info Card */}
        <Card variant="outlined">
          <Text variant="body" style={{ color: 'var(--foreground)' }}>
            <strong>Note:</strong> Your app will be accessible at{' '}
            <code style={{ background: 'rgba(0,0,0,0.1)', padding: '2px 4px', borderRadius: '4px', fontFamily: 'monospace' }}>
              {subdomain || 'subdomain'}.platform.com
            </code>
            . Make sure to choose a unique subdomain.
          </Text>
        </Card>
      </div>
    </Container>
  );
}

'use client';

import { useState, useMemo } from 'react';
import { useRouter } from 'next/navigation';
import { useTheme, useMediaQuery } from '@mui/material';
import { trpc } from '@/lib/trpc/client';
import { motion } from 'motion/react';
import { fadeInUp, staggerContainer, staggerItem } from '@/lib/animations/framer';
import { Heading, Text, Container, Alert } from '@/design-system';
import { designTokens } from '@/lib/theme/tokens';
import { SearchInput } from '@/design-system/atoms/inputs';
import { AppCard } from '@/components/ui/AppCard';
import { EmptyState } from '@/components/ui/EmptyState';
import { SkeletonMarketplaceCard } from '@/components/feedback/Skeleton';
import { mockApps, getAllCategories } from '@/lib/mock-data/apps';
import {
  Apps as AppsIcon,
  Assignment as AssignmentIcon,
  Code as CodeIcon,
  BarChart as BarChartIcon,
  Email as EmailIcon,
  Description as DescriptionIcon,
  CloudQueue as CloudIcon,
} from '@mui/icons-material';

// Icon mapping for categories
const categoryIcons: Record<string, React.ReactNode> = {
  Productivity: <AssignmentIcon />,
  Development: <CodeIcon />,
  Analytics: <BarChartIcon />,
  Communication: <EmailIcon />,
  Collaboration: <DescriptionIcon />,
  Storage: <CloudIcon />,
};

export default function AppsPage() {
  const router = useRouter();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('All');

  // Try to fetch real data, but use mock data as fallback for showcase
  const { data: realApps, isLoading, error } = (trpc as any).app.list.useQuery();

  // Use mock data if real data is empty or for showcase
  const apps = useMemo(() => {
    if (realApps && realApps.length > 0) {
      return realApps;
    }
    // Use mock data for showcase
    return mockApps.map((app: any) => ({
      id: app.id,
      name: app.name,
      subdomain: app.subdomain,
      description: app.description,
      status: app.status,
      created_at: app.created_at,
      category: app.category,
      tags: app.tags,
      screenshot: app.screenshot,
      icon: app.icon,
    }));
  }, [realApps]);

  const categories = useMemo(() => {
    return ['All', ...getAllCategories()];
  }, []);

  // Group apps by category
  const appsByCategory = useMemo(() => {
    const grouped: Record<string, typeof apps> = {};

    apps.forEach((app: any) => {
      const mockApp = mockApps.find((m: any) => m.id === app.id);
      const category = mockApp?.category || 'Other';

      // Apply filters
      if (selectedCategory !== 'All' && category !== selectedCategory) {
        return;
      }

      if (searchQuery) {
        const query = searchQuery.toLowerCase();
        const matches =
          app.name.toLowerCase().includes(query) ||
          app.subdomain.toLowerCase().includes(query) ||
          app.description?.toLowerCase().includes(query);
        if (!matches) return;
      }

      if (!grouped[category]) {
        grouped[category] = [];
      }
      grouped[category].push(app);
    });

    return grouped;
  }, [apps, searchQuery, selectedCategory]);

  // Get featured apps (if any)
  const featuredApps = useMemo(() => {
    return apps.filter((app: any) => {
      const mockApp = mockApps.find((m: any) => m.id === app.id);
      return mockApp && apps.indexOf(app as any) < 3;
    });
  }, [apps]);

  const handleViewDetails = (subdomain: string) => {
    router.push(`/apps/${subdomain}`);
  };

  const getAppCategory = (appId: string) => {
    const mockApp = mockApps.find((m: any) => m.id === appId);
    return mockApp?.category || 'Other';
  };

  const getAppIcon = (appId: string) => {
    const mockApp = mockApps.find((m: any) => m.id === appId);
    const category = mockApp?.category || 'Other';
    return categoryIcons[category] || <AppsIcon />;
  };

  if (isLoading) {
    return (
      <div
        style={{
          minHeight: '100vh',
          backgroundColor: 'var(--background)',
          padding: 'clamp(1rem, 2rem, 2rem)',
          width: '100%',
          maxWidth: '100%',
          boxSizing: 'border-box',
          overflowX: 'hidden',
        }}
      >
        <div style={{ display: 'flex', flexDirection: 'column', gap: 'clamp(1.5rem, 2rem, 2rem)', width: '100%', maxWidth: '100%' }}>
          <div>
            <div style={{ width: '60%', height: '32px', backgroundColor: 'var(--card)', borderRadius: '8px', marginBottom: '0.5rem' }} />
            <div style={{ width: '40%', height: '20px', backgroundColor: 'var(--card)', borderRadius: '8px' }} />
          </div>
          <div>
            <div style={{ width: '100%', height: '48px', backgroundColor: 'var(--card)', borderRadius: '8px' }} />
          </div>
          <div style={{ display: 'flex', gap: '0.5rem', overflowX: 'auto', paddingBottom: '0.5rem' }}>
            {[1, 2, 3, 4, 5].map((i: any) => (
              <div key={i} style={{ width: '80px', height: '32px', backgroundColor: 'var(--card)', borderRadius: '16px', flexShrink: 0 }} />
            ))}
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            {[1, 2, 3].map((i: any) => (
              <SkeletonMarketplaceCard key={i} />
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (error && !apps.length) {
    return (
      <div
        style={{
          minHeight: '100vh',
          backgroundColor: 'var(--background)',
          padding: 'clamp(1rem, 2rem, 2rem)',
          width: '100%',
          maxWidth: '100%',
          boxSizing: 'border-box',
          overflowX: 'hidden',
        }}
      >
        <Alert variant="error" message={error.message || 'Failed to load apps'} />
      </div>
    );
  }

  const categoryKeys = Object.keys(appsByCategory).sort();

  return (
    <motion.div
      initial="hidden"
      animate="visible"
      variants={fadeInUp}
      style={{
        minHeight: '100vh',
        backgroundColor: 'var(--background)',
        width: '100%',
        maxWidth: '100%',
        boxSizing: 'border-box',
        overflowX: 'hidden',
      }}
    >
      <Container 
        maxWidth={1400} 
        style={{ 
          padding: `clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']}) clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']})`,
          width: '100%',
          margin: '0 auto',
          boxSizing: 'border-box',
        }}
      >
        <div style={{ display: 'flex', flexDirection: 'column', gap: 'clamp(1.5rem, 2rem, 2rem)', width: '100%' }}>
          {/* Header Section */}
          <div style={{ width: '100%' }}>
            <Heading
              level={1}
              variant="title1"
              style={{
                marginBottom: '0.5rem',
                fontSize: 'clamp(1.75rem, 2.5rem, 2.5rem)',
                wordBreak: 'break-word',
              }}
            >
              App Marketplace
            </Heading>
            <Text
              variant="body"
              style={{
                color: 'var(--muted-foreground)',
                marginBottom: '1.5rem',
                wordBreak: 'break-word',
                fontSize: 'clamp(0.9375rem, 1rem, 1rem)',
              }}
            >
              Discover and launch powerful applications
            </Text>

            {/* Search Bar */}
            <div style={{ marginBottom: '1rem', width: '100%' }}>
              <SearchInput
                placeholder="Search apps..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                style={{ width: '100%' }}
              />
            </div>

            {/* Category Filters - Horizontal Scrollable */}
            <div
              style={{
                width: '100%',
                overflowX: 'auto',
                overflowY: 'hidden',
                WebkitOverflowScrolling: 'touch',
                paddingBottom: '0.5rem',
              }}
              className="scrollable-container"
            >
              <div
                style={{
                  display: 'flex',
                  flexDirection: 'row',
                  gap: '0.5rem',
                  width: 'max-content',
                  minWidth: '100%',
                }}
              >
                {categories.map((category: any) => (
                  <button
                    key={category}
                    onClick={() => setSelectedCategory(category)}
                    style={{
                      padding: '0.5rem 1rem',
                      borderRadius: '16px',
                      fontSize: isMobile ? '14px' : '13px',
                      fontWeight: 500,
                      cursor: 'pointer',
                      border: '1px solid var(--border)',
                      backgroundColor: selectedCategory === category
                        ? 'var(--popover)'
                        : 'transparent',
                      color: selectedCategory === category
                        ? 'var(--foreground)'
                        : 'var(--muted-foreground)',
                      flexShrink: 0,
                      minHeight: isMobile ? '36px' : '32px',
                      transition: 'all 0.2s ease',
                    }}
                    onMouseEnter={(e) => {
                      if (selectedCategory !== category) {
                        e.currentTarget.style.backgroundColor = 'rgba(255, 255, 255, 0.05)';
                      }
                    }}
                    onMouseLeave={(e) => {
                      if (selectedCategory !== category) {
                        e.currentTarget.style.backgroundColor = 'transparent';
                      }
                    }}
                  >
                    {category}
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Featured Section */}
          {featuredApps.length > 0 && !searchQuery && selectedCategory === 'All' && (
            <div style={{ width: '100%' }}>
              <Heading
                level={2}
                variant="title2"
                style={{
                  marginBottom: isMobile ? '1rem' : '1.5rem',
                }}
              >
                Featured
              </Heading>
              {isMobile ? (
                // Mobile: Vertical stack
                <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem', width: '100%' }}>
                  {featuredApps.map((app: any) => {
                    const category = getAppCategory(app.id);
                    const categoryIcon = getAppIcon(app.id);
                    const mockApp = mockApps.find((m: any) => m.id === app.id);
                    const isInstalled = app.status === 'installed' || app.status === 'approved';

                    return (
                      <div key={app.id} style={{ width: '100%' }}>
                        <AppCard
                          icon={categoryIcon}
                          name={app.name}
                          description={app.description}
                          category={category}
                          subdomain={app.subdomain}
                          status={isInstalled ? 'installed' : 'available'}
                          variant="marketplace"
                          imageUrl={mockApp?.screenshot}
                          href={`/apps/${app.subdomain}`}
                          onClick={() => handleViewDetails(app.subdomain)}
                        />
                      </div>
                    );
                  })}
                </div>
              ) : (
                // Desktop: Horizontal scroll
                <div
                  style={{
                    width: '100%',
                    overflowX: 'auto',
                    overflowY: 'hidden',
                    WebkitOverflowScrolling: 'touch',
                    paddingBottom: '1rem',
                  }}
                  className="scrollable-container"
                >
                  <div
                    style={{
                      display: 'flex',
                      flexDirection: 'row',
                      gap: '1rem',
                      width: 'max-content',
                      minWidth: '100%',
                    }}
                  >
                    {featuredApps.map((app: any) => {
                      const category = getAppCategory(app.id);
                      const categoryIcon = getAppIcon(app.id);
                      const mockApp = mockApps.find((m: any) => m.id === app.id);
                      const isInstalled = app.status === 'installed' || app.status === 'approved';

                      return (
                        <div
                          key={app.id}
                          style={{
                            flexShrink: 0,
                            width: '280px',
                            maxWidth: '280px',
                          }}
                        >
                          <AppCard
                            icon={categoryIcon}
                            name={app.name}
                            description={app.description}
                            category={category}
                            subdomain={app.subdomain}
                            status={isInstalled ? 'installed' : 'available'}
                            variant="marketplace"
                            imageUrl={mockApp?.screenshot}
                            href={`/apps/${app.subdomain}`}
                            onClick={() => handleViewDetails(app.subdomain)}
                          />
                        </div>
                      );
                    })}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Category Rows */}
          {categoryKeys.length > 0 ? (
            <motion.div
              variants={staggerContainer}
              initial="hidden"
              animate="visible"
              style={{ width: '100%' }}
            >
              <div style={{ display: 'flex', flexDirection: 'column', gap: 'clamp(1.5rem, 2rem, 2rem)', width: '100%' }}>
                {categoryKeys.map((category: any) => {
                  const categoryApps = appsByCategory[category];
                  if (!categoryApps || categoryApps.length === 0) return null;

                  return (
                    <motion.div key={category} variants={staggerItem} style={{ width: '100%' }}>
                      <Heading
                        level={2}
                        variant="title2"
                        style={{
                          marginBottom: isMobile ? '1rem' : '1.5rem',
                        }}
                      >
                        {category}
                      </Heading>
                      {isMobile ? (
                        // Mobile: Vertical stack
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem', width: '100%' }}>
                          {categoryApps.map((app: any) => {
                            const categoryIcon = getAppIcon(app.id);
                            const mockApp = mockApps.find((m: any) => m.id === app.id);
                            const isInstalled = app.status === 'installed' || app.status === 'approved';

                            return (
                              <div key={app.id} style={{ width: '100%' }}>
                                <AppCard
                                  icon={categoryIcon}
                                  name={app.name}
                                  description={app.description}
                                  category={category}
                                  subdomain={app.subdomain}
                                  status={isInstalled ? 'installed' : 'available'}
                                  variant="marketplace"
                                  imageUrl={mockApp?.screenshot}
                                  href={`/apps/${app.subdomain}`}
                                  onClick={() => handleViewDetails(app.subdomain)}
                                />
                              </div>
                            );
                          })}
                        </div>
                      ) : (
                        // Desktop: Horizontal scroll
                        <div
                          style={{
                            width: '100%',
                            overflowX: 'auto',
                            overflowY: 'hidden',
                            WebkitOverflowScrolling: 'touch',
                            paddingBottom: '1rem',
                          }}
                          className="scrollable-container"
                        >
                          <div
                            style={{
                              display: 'flex',
                              flexDirection: 'row',
                              gap: '1rem',
                              width: 'max-content',
                              minWidth: '100%',
                            }}
                          >
                            {categoryApps.map((app: any) => {
                              const categoryIcon = getAppIcon(app.id);
                              const mockApp = mockApps.find((m: any) => m.id === app.id);
                              const isInstalled = app.status === 'installed' || app.status === 'approved';

                              return (
                                <div
                                  key={app.id}
                                  style={{
                                    flexShrink: 0,
                                    width: '280px',
                                    maxWidth: '280px',
                                  }}
                                >
                                  <AppCard
                                    icon={categoryIcon}
                                    name={app.name}
                                    description={app.description}
                                    category={category}
                                    subdomain={app.subdomain}
                                    status={isInstalled ? 'installed' : 'available'}
                                    variant="marketplace"
                                    imageUrl={mockApp?.screenshot}
                                    href={`/apps/${app.subdomain}`}
                                    onClick={() => handleViewDetails(app.subdomain)}
                                  />
                                </div>
                              );
                            })}
                          </div>
                        </div>
                      )}
                    </motion.div>
                  );
                })}
              </div>
            </motion.div>
          ) : (
            <EmptyState
              icon={<AppsIcon />}
              title={searchQuery || selectedCategory !== 'All' ? 'No apps found' : 'No apps available'}
              description={
                searchQuery || selectedCategory !== 'All'
                  ? `No apps match your filters. Try adjusting your search or category.`
                  : 'There are no apps available in the marketplace at this time. Check back later!'
              }
            />
          )}
        </div>
      </Container>

      <style jsx>{`
        .scrollable-container::-webkit-scrollbar {
          height: 8px;
        }
        .scrollable-container::-webkit-scrollbar-track {
          background: transparent;
        }
        .scrollable-container::-webkit-scrollbar-thumb {
          background: var(--border);
          border-radius: 4px;
        }
      `}</style>
    </motion.div>
  );
}

'use client';

import { useMemo, useState } from 'react';
import dynamic from 'next/dynamic';
import { Heading, Text, Container, Card, Button, Badge, Alert, Modal, Divider, IconButton } from '@/design-system';
import { designTokens } from '@/lib/theme/tokens';
import { TextField } from '@/components/forms/TextField';
import { ContentCopy as ContentCopyIcon, Check as CheckIcon, HelpOutline as HelpOutlineIcon, Visibility, VisibilityOff } from '@mui/icons-material';
import { trpc } from '@/lib/trpc/client';
import { LoadingSpinner } from '@/components/feedback/LoadingSpinner';

// Lazy load syntax highlighter with style (heavy component, client-only)
const SyntaxHighlighter = dynamic(
  () =>
    Promise.all([
      import('react-syntax-highlighter').then(mod => mod.Prism),
      import('react-syntax-highlighter/dist/esm/styles/prism').then(mod => mod.vscDarkPlus)
    ]).then(([Prism, style]) => {
      // Create a wrapper component that includes the style
      const HighlighterWrapper = (props: any) => <Prism style={style} {...props} />;
      HighlighterWrapper.displayName = 'SyntaxHighlighterWrapper';
      return HighlighterWrapper;
    }),
  {
    ssr: false,
    loading: () => <div style={{ padding: '1rem' }}>Loading code...</div>
  }
);

type EmbedTokenResult = {
  token: string;
  expiresIn?: number;
};

type CreateFormState = {
  appId: string;
  name: string;
  description: string;
  allowedOrigins: string;
  embedTokenTtlSeconds: number;
  mode: 'basic' | 'advanced';
  pwaUrl: string;
};

const initialForm: CreateFormState = {
  appId: '',
  name: '',
  description: '',
  allowedOrigins: '',
  embedTokenTtlSeconds: 600,
  mode: 'basic',
  pwaUrl: '',
};

const normalizeOrigins = (value: string) =>
  value
    .split(/[\n,]/)
    .map((o: any) => o.trim())
    .filter(Boolean);

const toOrigin = (url: string) => {
  try {
    const parsed = new URL(url);
    return `${parsed.protocol}//${parsed.host}`;
  } catch {
    return null;
  }
};

function DeveloperAppCard({
  app,
  onIssueToken,
  onRotate,
  issuing,
  rotating,
  issueError,
  issuedToken,
}: {
  app: any;
  onIssueToken: (origin: string) => void;
  onRotate: () => void;
  issuing: boolean;
  rotating: boolean;
  issueError?: string | null;
  issuedToken?: EmbedTokenResult | null;
}) {
  const [originInput, setOriginInput] = useState('');
  const [showToken, setShowToken] = useState(false);
  const [showSnippetToken, setShowSnippetToken] = useState(false);
  const [appIdCopied, setAppIdCopied] = useState(false);
  const [tokenCopied, setTokenCopied] = useState(false);
  const [snippetCopied, setSnippetCopied] = useState(false);

  const handleCopyAppId = async () => {
    try {
      await navigator.clipboard.writeText(app.app_id);
      setAppIdCopied(true);
      setTimeout(() => setAppIdCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy AppID:', err);
    }
  };

  const handleCopyToken = async () => {
    if (!issuedToken?.token) return;
    try {
      await navigator.clipboard.writeText(issuedToken.token);
      setTokenCopied(true);
      setTimeout(() => setTokenCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy token:', err);
    }
  };

  const embedConfigSnippet = `const appId = '${app.app_id}';
const embedToken = '${issuedToken?.token || '<ISSUE_TOKEN_FIRST>'}'`;

  const embedConfigSnippetRedacted = `const appId = '${app.app_id}';
const embedToken = '${issuedToken?.token ? '••••••••••••••••' : '<ISSUE_TOKEN_FIRST>'}'`;

  const handleCopySnippet = async () => {
    const snippetToCopy = showSnippetToken && issuedToken?.token
      ? embedConfigSnippet
      : embedConfigSnippetRedacted;
    try {
      await navigator.clipboard.writeText(snippetToCopy);
      setSnippetCopied(true);
      setTimeout(() => setSnippetCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy snippet:', err);
    }
  };

  return (
    <Card variant="outlined">
      <div style={{ padding: '1.5rem' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1rem' }}>
          <div>
            <Heading level={3} variant="headline" style={{ marginBottom: '0.25rem' }}>
              {app.name}
            </Heading>
            <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
              {app.description || 'No description provided'}
            </Text>
          </div>
          <Badge variant={app.status === 'active' ? 'success' : 'warning'} size="sm">
            {app.status}
          </Badge>
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
          <div>
            <Text variant="caption1" weight="semibold" style={{ display: 'block', marginBottom: '0.25rem' }}>
              Linked app
            </Text>
            <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
              {app.app?.name} · {app.app?.subdomain}
            </Text>
          </div>

          <div>
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
              <Text variant="caption1" weight="semibold">App ID</Text>
              <IconButton
                icon={appIdCopied ? <CheckIcon style={{ fontSize: '18px', color: 'var(--success)' }} /> : <ContentCopyIcon style={{ fontSize: '18px' }} />}
                onClick={handleCopyAppId}
                size="small"
                aria-label={appIdCopied ? 'Copied!' : 'Copy App ID'}
              />
            </div>
            <div style={{ position: 'relative' }}>
              <TextField
                value={app.app_id}
                fullWidth
                InputProps={{
                  readOnly: true,
                }}
                style={{
                  fontFamily: 'monospace',
                  fontSize: '0.875rem',
                }}
              />
              <div style={{ position: 'absolute', right: '12px', top: '50%', transform: 'translateY(-50%)' }}>
                <IconButton
                  icon={appIdCopied ? <CheckIcon style={{ fontSize: '18px', color: 'var(--success)' }} /> : <ContentCopyIcon style={{ fontSize: '18px' }} />}
                  onClick={handleCopyAppId}
                  size="small"
                  aria-label={appIdCopied ? 'Copied!' : 'Copy App ID'}
                />
              </div>
            </div>
            <Text variant="caption1" style={{ color: 'var(--muted-foreground)', marginTop: '0.25rem', display: 'block' }}>
              Use this App ID in your embed configuration
            </Text>
          </div>

          <div>
            <Text variant="caption1" weight="semibold" style={{ display: 'block', marginBottom: '0.5rem' }}>
              Allowed origins
            </Text>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem' }}>
              {app.allowed_origins?.length ? (
                app.allowed_origins.map((origin: string) => (
                  <Badge key={origin} variant="default" size="sm">{origin}</Badge>
                ))
              ) : (
                <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
                  None configured
                </Text>
              )}
            </div>
          </div>

          <div>
            <Text variant="caption1" weight="semibold" style={{ display: 'block', marginBottom: '0.25rem' }}>
              Embed public key
            </Text>
            <Text variant="body" style={{ color: 'var(--muted-foreground)', wordBreak: 'break-all', fontFamily: 'monospace', fontSize: '0.875rem' }}>
              {app.embed_public_key}
            </Text>
          </div>

          <div>
            <Text variant="caption1" weight="semibold" style={{ display: 'block', marginBottom: '0.5rem' }}>
              Issue embed token
            </Text>
            <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap', marginBottom: '0.5rem' }}>
              <TextField
                label="Origin (must be allowed)"
                value={originInput}
                onChange={(e) => setOriginInput(e.target.value)}
                fullWidth
                style={{ flex: 1, minWidth: '200px' }}
              />
              <Button
                variant="primary"
                onClick={() => onIssueToken(originInput)}
                loading={issuing}
                disabled={!originInput}
              >
                Issue token
              </Button>
            </div>
            {issueError ? (
              <Alert variant="error" message={issueError} className="mb-2" />
            ) : issuedToken ? (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                <div style={{ position: 'relative' }}>
                  <TextField
                    label="Embed token"
                    type={showToken ? 'text' : 'password'}
                    value={issuedToken.token}
                    fullWidth
                    InputProps={{
                      readOnly: true,
                    }}
                    style={{
                      fontFamily: 'monospace',
                      fontSize: '0.875rem',
                    }}
                  />
                  <div style={{ position: 'absolute', right: '12px', top: '50%', transform: 'translateY(-50%)', display: 'flex', gap: '0.25rem' }}>
                    <IconButton
                      icon={showToken ? <VisibilityOff style={{ fontSize: '18px' }} /> : <Visibility style={{ fontSize: '18px' }} />}
                      onClick={() => setShowToken(!showToken)}
                      size="small"
                      aria-label={showToken ? 'Hide token' : 'Show token'}
                    />
                    <IconButton
                      icon={tokenCopied ? <CheckIcon style={{ fontSize: '18px', color: 'var(--success)' }} /> : <ContentCopyIcon style={{ fontSize: '18px' }} />}
                      onClick={handleCopyToken}
                      size="small"
                      aria-label={tokenCopied ? 'Copied!' : 'Copy token'}
                    />
                  </div>
                </div>
                {issuedToken.expiresIn && (
                  <Text variant="caption1" style={{ color: 'var(--muted-foreground)' }}>
                    Expires in {issuedToken.expiresIn} seconds
                  </Text>
                )}
              </div>
            ) : null}
          </div>

          {issuedToken && (
            <div>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                <Text variant="caption1" weight="semibold">Embed Configuration</Text>
                <div style={{ display: 'flex', gap: '0.25rem' }}>
                  {issuedToken?.token && (
                    <IconButton
                      icon={showSnippetToken ? <VisibilityOff style={{ fontSize: '18px' }} /> : <Visibility style={{ fontSize: '18px' }} />}
                      onClick={() => setShowSnippetToken(!showSnippetToken)}
                      size="small"
                      aria-label={showSnippetToken ? 'Hide token in snippet' : 'Show token in snippet'}
                    />
                  )}
                  <IconButton
                    icon={snippetCopied ? <CheckIcon style={{ fontSize: '18px', color: 'var(--success)' }} /> : <ContentCopyIcon style={{ fontSize: '18px' }} />}
                    onClick={handleCopySnippet}
                    size="small"
                    aria-label={snippetCopied ? 'Copied!' : 'Copy code snippet'}
                  />
                </div>
              </div>
              <TextField
                multiline
                rows={2}
                value={showSnippetToken && issuedToken?.token ? embedConfigSnippet : embedConfigSnippetRedacted}
                fullWidth
                InputProps={{
                  readOnly: true,
                }}
                style={{
                  fontFamily: 'monospace',
                  fontSize: '0.875rem',
                }}
              />
              <Text variant="caption1" style={{ color: 'var(--muted-foreground)', marginTop: '0.25rem', display: 'block' }}>
                Ready-to-use code snippet. Copy and paste into your PWA integration code.
              </Text>
            </div>
          )}

          <Divider />

          <Button variant="outline" onClick={onRotate} loading={rotating} disabled={rotating}>
            Rotate secrets
          </Button>
        </div>
      </div>
    </Card>
  );
}

export default function DeveloperToolsPage() {
  const [form, setForm] = useState<CreateFormState>(initialForm);
  const [formError, setFormError] = useState<string | null>(null);
  const [issueStates, setIssueStates] = useState<Record<string, EmbedTokenResult | null>>({});
  const [issueErrors, setIssueErrors] = useState<Record<string, string | null>>({});
  const [copied, setCopied] = useState(false);
  const [promptCopied, setPromptCopied] = useState(false);
  const [exampleCopied, setExampleCopied] = useState(false);
  const [nextStepsPromptCopied, setNextStepsPromptCopied] = useState(false);
  const [supportDialogOpen, setSupportDialogOpen] = useState(false);
  const [supportForm, setSupportForm] = useState({
    name: '',
    email: '',
    subject: '',
    message: '',
  });
  const [supportFormError, setSupportFormError] = useState<string | null>(null);
  const [supportFormSubmitting, setSupportFormSubmitting] = useState(false);

  const { data: apps } = (trpc as any).app.list.useQuery();
  const { data: developerApps, refetch, isLoading, error } = (trpc as any).developerApp.list.useQuery();

  const createMutation = (trpc as any).developerApp.create.useMutation({
    onSuccess: () => {
      setForm(initialForm);
      refetch();
    },
    onError: (err: any) => setFormError(err.message),
  });

  const issueMutation = (trpc as any).developerApp.issueEmbedToken.useMutation();
  const rotateMutation = (trpc as any).developerApp.rotateSecrets.useMutation({
    onSuccess: () => refetch(),
  });

  const appOptions = useMemo(() => apps || [], [apps]);

  const deriveOrigins = () => {
    const dashboardOrigin =
      typeof window !== 'undefined'
        ? `${window.location.protocol}//${window.location.host}`
        : '';

    if (form.mode === 'basic') {
      const derived: string[] = [];
      if (dashboardOrigin) derived.push(dashboardOrigin);
      const pwaOrigin = toOrigin(form.pwaUrl.trim());
      if (pwaOrigin) derived.push(pwaOrigin);
      return Array.from(new Set(derived)).filter(Boolean);
    }

    return normalizeOrigins(form.allowedOrigins);
  };

  const handleCreate = () => {
    setFormError(null);
    const origins = deriveOrigins();
    if (!form.appId || !form.name || !origins.length) {
      setFormError('App, name, and at least one origin are required.');
      return;
    }

    createMutation.mutate({
      appId: form.appId,
      name: form.name,
      description: form.description,
      allowedOrigins: origins,
      embedTokenTtlSeconds: form.embedTokenTtlSeconds,
    });
  };

  const handleIssueToken = async (developerAppId: string, origin: string) => {
    setIssueErrors((prev) => ({ ...prev, [developerAppId]: null }));
    setIssueStates((prev) => ({ ...prev, [developerAppId]: null }));
    try {
      const result = await issueMutation.mutateAsync({
        developerAppId,
        origin,
      });
      setIssueStates((prev) => ({ ...prev, [developerAppId]: result }));
    } catch (err: any) {
      setIssueErrors((prev) => ({ ...prev, [developerAppId]: err.message || 'Failed to issue token' }));
    }
  };

  const handleRotate = async (developerAppId: string) => {
    await rotateMutation.mutateAsync({ id: developerAppId });
  };

  const embedSnippet = `<script src="https://your-marketplace.com/embed-sdk.js"></script>
<script>
  const appId = '<APP_ID>';
  const embedToken = '<EMBED_TOKEN>'; // Issued for this origin

  async function loginToMarketplace() {
    try {
      const result = await window.MarketplaceEmbed.authenticate({
        appId,
        embedToken,
        baseUrl: 'https://your-marketplace.com'
      });
      // result.token is the short-lived JWT for your PWA
      // Use this token to authenticate API requests
      console.log('Authenticated:', result);
    } catch (error) {
      console.error('Authentication failed:', error);
    }
  }
</script>`;

  const aiPrompt = `Add marketplace authentication to my PWA login page. Include the embed SDK script tag, create a loginToMarketplace() async function that calls window.MarketplaceEmbed.authenticate() with appId, embedToken, and baseUrl. Handle success (store the JWT token) and errors (show user-friendly message). Add a "Sign in with Marketplace" button that calls this function on click. Use the following code structure:`;

  const nextStepsAiPrompt = `After successful marketplace authentication, handle the result.token properly: Store it securely (localStorage/sessionStorage), treat it as successful authentication allowing full app access, include it in API requests as Bearer token in Authorization header, handle token expiration by re-authenticating when needed, and update app state to set user as authenticated and redirect to dashboard/home. Use the enhanced authentication handler pattern shown in the example code.`;

  const exampleCode = `async function loginToMarketplace() {
  try {
    const result = await window.MarketplaceEmbed.authenticate({
      appId,
      embedToken,
      baseUrl: 'https://your-marketplace.com'
    });

    // Store token securely
    localStorage.setItem('marketplace_token', result.token);

    // Update app state - user is now authenticated
    setUserAuthenticated(true);

    // Redirect to app dashboard/home
    window.location.href = '/dashboard/home';

  } catch (error) {
    // Handle errors gracefully
    showErrorMessage('Authentication failed. Please try again.');
  }
}`;

  const handleCopySnippet = async () => {
    try {
      await navigator.clipboard.writeText(embedSnippet);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy:', err);
    }
  };

  const handleCopyPrompt = async () => {
    try {
      await navigator.clipboard.writeText(aiPrompt);
      setPromptCopied(true);
      setTimeout(() => setPromptCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy:', err);
    }
  };

  const handleCopyExample = async () => {
    try {
      await navigator.clipboard.writeText(exampleCode);
      setExampleCopied(true);
      setTimeout(() => setExampleCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy:', err);
    }
  };

  const handleCopyNextStepsPrompt = async () => {
    try {
      await navigator.clipboard.writeText(nextStepsAiPrompt);
      setNextStepsPromptCopied(true);
      setTimeout(() => setNextStepsPromptCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy:', err);
    }
  };

  const handleSupportDialogOpen = () => {
    setSupportDialogOpen(true);
  };

  const handleSupportDialogClose = () => {
    setSupportDialogOpen(false);
    setSupportForm({
      name: '',
      email: '',
      subject: '',
      message: '',
    });
    setSupportFormError(null);
  };

  const handleSupportFormSubmit = async () => {
    setSupportFormError(null);

    if (!supportForm.name || !supportForm.email || !supportForm.message) {
      setSupportFormError('Please fill in all required fields.');
      return;
    }

    setSupportFormSubmitting(true);
    try {
      // TODO: Implement actual support form submission (email API, webhook, etc.)
      // For now, just log and show success
      console.log('Support form submitted:', supportForm);

      // Simulate API call
      await new Promise((resolve) => setTimeout(resolve, 1000));

      // Show success and close
      handleSupportDialogClose();
      // You could show a success toast here
    } catch (err: any) {
      setSupportFormError(err.message || 'Failed to submit support request. Please try again.');
    } finally {
      setSupportFormSubmitting(false);
    }
  };

  return (
    <div
      style={{
        minHeight: '100vh',
        backgroundColor: 'var(--background)',
        width: '100%',
        boxSizing: 'border-box',
      }}
    >
      <Container
        maxWidth={1200}
        style={{
          padding: `clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']}) clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']})`,
          width: '100%',
          margin: '0 auto',
          boxSizing: 'border-box',
        }}
      >
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
          <div>
