                      width: '100%',
                      padding: '0.75rem',
                      borderRadius: '10px',
                      border: '1px solid var(--border)',
                      backgroundColor: 'var(--card)',
                      color: 'var(--foreground)',
                      fontSize: '15px',
                      minHeight: '44px',
