                </Text>
              </div>

              <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                <div>
                  <Heading level={3} variant="headline" style={{ marginBottom: '1rem', fontSize: '1.125rem' }}>
                    Quick start
                  </Heading>
                  <Alert variant="info" message="Add to your PWA's login page. Call loginToMarketplace() when user clicks 'Sign in with Marketplace'. Replace APP_ID and EMBED_TOKEN with values from above. Update baseUrl to match your marketplace domain." />
                </div>

                <div>
                  <div>
                    <Alert variant="success" message="Using an AI coding assistant or IDE? Copy the prompt below to help your assistant integrate this correctly." />
                    <div style={{ marginTop: '0.5rem', display: 'flex', justifyContent: 'flex-end' }}>
                      <IconButton
                        icon={promptCopied ? <CheckIcon style={{ fontSize: '18px', color: 'var(--success)' }} /> : <ContentCopyIcon style={{ fontSize: '18px' }} />}
                        onClick={handleCopyPrompt}
                        size="small"
                        aria-label={promptCopied ? 'Copied!' : 'Copy prompt to clipboard'}
                      />
                    </div>
                    <div
                      style={{
                        backgroundColor: 'var(--popover)',
                        border: '1px solid var(--border)',
                        borderRadius: '8px',
                        padding: '0.75rem',
                        marginTop: '0.5rem',
                      }}
                    >
                      <pre
                        style={{
                          fontFamily: 'monospace',
                          fontSize: '0.75rem',
                          margin: 0,
                          whiteSpace: 'pre-wrap',
                          wordBreak: 'break-word',
                          lineHeight: 1.6,
                          color: 'var(--foreground)',
                        }}
                      >
                        {aiPrompt}
                      </pre>
                    </div>
                  </div>
                </div>

                <div>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                    <Heading level={3} variant="headline" style={{ fontSize: '1.125rem' }}>
                      JavaScript code snippet
                    </Heading>
                    <IconButton
                      icon={copied ? <CheckIcon style={{ fontSize: '18px', color: 'var(--success)' }} /> : <ContentCopyIcon style={{ fontSize: '18px' }} />}
                      onClick={handleCopySnippet}
                      size="small"
                      aria-label={copied ? 'Copied!' : 'Copy to clipboard'}
                    />
                  </div>
                  <div
                    style={{
                      border: '1px solid var(--border)',
                      borderRadius: '8px',
                      overflow: 'hidden',
                    }}
                  >
                    <SyntaxHighlighter
                      language="javascript"
                      customStyle={{
                        margin: 0,
                        padding: '1.75rem',
                        backgroundColor: 'var(--popover)',
                        fontSize: '0.875rem',
                        lineHeight: 1.7,
                      }}
                    >
                      {embedSnippet}
                    </SyntaxHighlighter>
                  </div>
                </div>

                <Divider />

                <div>
                  <Heading level={3} variant="headline" style={{ marginBottom: '1rem', fontSize: '1.125rem' }}>
                    Recommended next steps
                  </Heading>
                  <Alert variant="warning" message="Handle successful authentication: Store token securely, treat as successful auth, include in API requests as Bearer token, handle expiration." />
                  <div
                    style={{
                      backgroundColor: 'var(--popover)',
                      border: '1px solid var(--border)',
                      borderRadius: '8px',
                      padding: '0.75rem',
                      marginTop: '0.5rem',
                    }}
                  >
                    <pre
                      style={{
                        fontFamily: 'monospace',
                        fontSize: '0.75rem',
                        margin: 0,
                        whiteSpace: 'pre-wrap',
                        wordBreak: 'break-word',
                        lineHeight: 1.6,
                        color: 'var(--foreground)',
                      }}
                    >
                      {nextStepsAiPrompt}
                    </pre>
                  </div>

                  <div style={{ marginTop: '1rem' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.75rem' }}>
                      <Text variant="body" weight="medium">
                        Example: Enhanced authentication handler
                      </Text>
                      <IconButton
                        icon={exampleCopied ? <CheckIcon style={{ fontSize: '18px', color: 'var(--success)' }} /> : <ContentCopyIcon style={{ fontSize: '18px' }} />}
                        onClick={handleCopyExample}
                        size="small"
                        aria-label={exampleCopied ? 'Copied!' : 'Copy to clipboard'}
                      />
                    </div>
                    <div
                      style={{
                        border: '1px solid var(--border)',
                        borderRadius: '8px',
                        overflow: 'hidden',
                      }}
                    >
                      <SyntaxHighlighter
                        language="javascript"
                        customStyle={{
                          margin: 0,
                          padding: '1.5rem',
                          backgroundColor: 'var(--popover)',
                          fontSize: '0.875rem',
                          lineHeight: 1.7,
                        }}
                      >
                        {exampleCode}
                      </SyntaxHighlighter>
                    </div>
                  </div>
                </div>

                <Divider />

                <div style={{ display: 'flex', justifyContent: 'center' }}>
                  <Button
                    variant="outline"
                    onClick={handleSupportDialogOpen}
                    style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}
                  >
                    <HelpOutlineIcon style={{ fontSize: '18px' }} />
                    Need Help?
                  </Button>
                </div>
              </div>
            </div>
          </Card>

          <Modal
            open={supportDialogOpen}
            onClose={handleSupportDialogClose}
            title="Contact Support"
            variant="centered"
          >
            <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
              <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
                Need help with embedding? We're here to assist you.
              </Text>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                <TextField
                  label="Your name"
                  value={supportForm.name}
                  onChange={(e) => setSupportForm((prev) => ({ ...prev, name: e.target.value }))}
                  fullWidth
                  required
                />
                <TextField
                  label="Email address"
                  type="email"
                  value={supportForm.email}
                  onChange={(e) => setSupportForm((prev) => ({ ...prev, email: e.target.value }))}
                  fullWidth
                  required
                  helperText="We'll use this to respond to your inquiry"
                />
                <TextField
                  label="Subject"
                  value={supportForm.subject}
                  onChange={(e) => setSupportForm((prev) => ({ ...prev, subject: e.target.value }))}
                  fullWidth
                  placeholder="e.g., Integration help, Token issues, etc."
                />
                <TextField
                  label="Message"
                  value={supportForm.message}
                  onChange={(e) => setSupportForm((prev) => ({ ...prev, message: e.target.value }))}
                  multiline
                  rows={4}
                  fullWidth
                  required
                  placeholder="Describe your issue or question..."
                  helperText="Include details about your integration, error messages, or what you're trying to achieve"
                />
                {supportFormError && (
                  <Alert variant="error" message={supportFormError} />
                )}
              </div>
              <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end' }}>
                <Button onClick={handleSupportDialogClose} variant="outline">
                  Cancel
                </Button>
                <Button
                  variant="primary"
                  onClick={handleSupportFormSubmit}
                  loading={supportFormSubmitting}
                  disabled={!supportForm.name || !supportForm.email || !supportForm.message}
                >
                  Send Message
                </Button>
              </div>
            </div>
          </Modal>

          <Divider />

          <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            <Heading level={2} variant="headline">Existing developer apps</Heading>
            {isLoading && <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '0.5rem' }}><LoadingSpinner size="medium" /><span style={{ color: 'var(--muted-foreground)', fontSize: '0.875rem' }}>Loading...</span></div>}
            {error && <Alert variant="error" message={error.message} />}
            {!isLoading && developerApps && developerApps.length === 0 ? (
              <Alert variant="info" message="No developer apps yet. Create one to get started." />
            ) : null}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
              {developerApps?.map((devApp: any) => (
                <DeveloperAppCard
                  key={devApp.id}
                  app={devApp}
                  issuing={issueMutation.isLoading}
                  rotating={rotateMutation.isLoading}
                  issuedToken={issueStates[devApp.id]}
                  issueError={issueErrors[devApp.id]}
                  onIssueToken={(origin) => handleIssueToken(devApp.id, origin)}
                  onRotate={() => handleRotate(devApp.id)}
                />
              ))}
            </div>
          </div>
        </div>
      </Container>
    </div>
  );
}

'use client';

import { useAuth } from '@/contexts/AuthContext';
import { trpc } from '@/lib/trpc/client';
import { Heading, Text, Container, Card, Label, Button, Badge } from '@/design-system';
import { designTokens } from '@/lib/theme/tokens';
import Link from 'next/link';
import { useTheme, useMediaQuery } from '@mui/material';
import {
  ShoppingBag as ShoppingBagIcon,
  Store as StoreIcon,
  TrendingUp as TrendingUpIcon,
  Email as EmailIcon,
  Person as PersonIcon,
  Business as BusinessIcon,
  ArrowForward as ArrowForwardIcon,
} from '@mui/icons-material';

export default function HomePage() {
  const { user } = useAuth();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));

  const { data: tenant } = (trpc as any).tenant.get.useQuery();
  const { data: purchases, isLoading: purchasesLoading } = (trpc as any).deal.getMyPurchases.useQuery();
  const { data: deals, isLoading: dealsLoading } = (trpc as any).deal.getMyDeals.useQuery();
  const { data: sellerStats, isLoading: sellerStatsLoading } = (trpc as any).seller.dashboard.useQuery(
    undefined,
    { enabled: !!deals && deals.length > 0, retry: false }
  );

  const purchaseCount = purchases?.length || 0;
  const totalListings = deals?.length || 0;
  const activeListings = deals?.filter((d: any) => d.status === 'live' || d.status === 'approved').length || 0;
  const totalSellerRevenue = sellerStats?.revenue?.totalSellerRevenue || 0;

  const hasBuyer = purchaseCount > 0;
  const hasSeller = totalListings > 0;
  const gridCols = isMobile ? '1fr' : '2fr 1fr';
  const buyerSpan = hasBuyer && hasSeller ? undefined : '1 / -1';
  const sellerSpan = hasSeller && hasBuyer ? undefined : '1 / -1';

  return (
    <Container
      maxWidth={800}
      style={{
        padding: `clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']}) clamp(${designTokens.spacing.lg}, ${designTokens.spacing.xl}, ${designTokens.spacing['2xl']})`,
        width: '100%',
        boxSizing: 'border-box',
      }}
    >
      <div style={{ display: 'flex', flexDirection: 'column', gap: designTokens.spacing['2xl'] }}>
        {/* Welcome Section */}
        <div>
          <Heading
            level={1}
            variant="largeTitle"
            style={{
              fontSize: 'clamp(1.75rem, 2.5rem, 2.5rem)',
              marginBottom: designTokens.spacing.md,
              color: designTokens.colors.text.primary,
            }}
          >
            Welcome back
          </Heading>
          <Text variant="body" style={{ color: designTokens.colors.text.secondary }}>
            {user?.email}
          </Text>
        </div>

        {/* Asymmetric grid: hero card full width, then Buyer | Seller cards */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: gridCols,
            gap: designTokens.spacing['2xl'],
          }}
        >
          {/* Hero card: Account Information */}
          <Card variant="elevated" style={{ gridColumn: '1 / -1' }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: designTokens.spacing.xl }}>
              <Heading
                level={2}
                variant="title2"
                style={{
                  fontSize: 'clamp(1.25rem, 1.5rem, 1.5rem)',
                  marginBottom: designTokens.spacing.xl,
                  color: designTokens.colors.text.primary,
                }}
              >
                Account Information
              </Heading>
              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                  gap: designTokens.spacing.xl,
                }}
              >
                <div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: designTokens.spacing.sm, marginBottom: designTokens.spacing.xs }}>
                    <EmailIcon style={{ fontSize: '18px', color: designTokens.colors.action.primary }} />
                    <Label style={{ color: designTokens.colors.text.secondary }}>Email</Label>
                  </div>
                  <Text variant="body" weight="medium" style={{ color: designTokens.colors.text.primary }}>
                    {user?.email}
                  </Text>
                </div>
                <div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: designTokens.spacing.sm, marginBottom: designTokens.spacing.xs }}>
                    <PersonIcon style={{ fontSize: '18px', color: designTokens.colors.action.primary }} />
                    <Label style={{ color: designTokens.colors.text.secondary }}>User ID</Label>
                  </div>
                  <Text
                    variant="caption1"
                    style={{
                      color: designTokens.colors.text.secondary,
                      wordBreak: 'break-all',
                      fontFamily: designTokens.typography.fontFamily.mono,
                    }}
                  >
                    {user?.id}
                  </Text>
                </div>
                {tenant && (
                  <div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: designTokens.spacing.sm, marginBottom: designTokens.spacing.xs }}>
                      <BusinessIcon style={{ fontSize: '18px', color: designTokens.colors.action.primary }} />
                      <Label style={{ color: designTokens.colors.text.secondary }}>Tenant</Label>
                    </div>
                    <Text variant="body" weight="medium" style={{ color: designTokens.colors.text.primary }}>
                      {tenant.name}
                    </Text>
                    <span style={{ marginTop: designTokens.spacing.xs, display: 'inline-block' }}>
                      <Badge variant="default" size="sm">Free Plan</Badge>
                    </span>
                  </div>
                )}
              </div>
            </div>
          </Card>

