                    display: 'flex',
                    flexDirection: 'column',
                    gap: designTokens.spacing.lg,
                    padding: designTokens.spacing.lg,
                    background: designTokens.colors.surface.subtle,
                    borderRadius: designTokens.borderRadius.md,
