function ReviewModal({
  purchaseId,
  open,
  onClose,
  onSuccess,
}: {
  purchaseId: string;
  open: boolean;
  onClose: () => void;
  onSuccess: () => void;
}) {
  const { data: purchase } = (trpc as any).purchase.getMyPurchases.useQuery();
  const currentPurchase = purchase?.find((p: any) => p.id === purchaseId);
  const { data: myReview, refetch: refetchMyReview } = (trpc as any).marketplace.getMyReview.useQuery(
    { purchase_id: purchaseId },
    { enabled: open && !!purchaseId }
  );

  const submitReviewMutation = (trpc as any).marketplace.submitReview.useMutation({
    onSuccess: () => {
      onSuccess();
      refetchMyReview();
    },
  });

  const updateReviewMutation = (trpc as any).marketplace.updateReview.useMutation({
    onSuccess: () => {
      onSuccess();
      refetchMyReview();
    },
  });

  const handleSubmit = async (rating: number, reviewText: string) => {
    if (!currentPurchase || !currentPurchase.deal_id) {
      return;
    }

    if (myReview) {
      await updateReviewMutation.mutateAsync({
        review_id: myReview.id,
        rating,
        review_text: reviewText || undefined,
      });
    } else {
      await submitReviewMutation.mutateAsync({
        deal_id: currentPurchase.deal_id,
        purchase_id: purchaseId,
        rating,
        review_text: reviewText || undefined,
      });
    }
  };

  if (!currentPurchase) {
    return null;
  }

  return (
    <Modal
      open={open}
      onClose={onClose}
      title={myReview ? 'Edit Your Review' : 'Write a Review'}
    >
      <ReviewForm
        initialRating={myReview ? myReview.rating : 0}
        initialReviewText={myReview ? myReview.review_text || '' : ''}
        onSubmit={handleSubmit}
        onCancel={onClose}
        isLoading={submitReviewMutation.isLoading || updateReviewMutation.isLoading}
        error={
          submitReviewMutation.error?.message ||
          updateReviewMutation.error?.message ||
          null
        }
        mode={myReview ? 'edit' : 'create'}
      />
    </Modal>
  );
}

