                  <Button
                    type="submit"
                    variant="primary"
                    fullWidth
                    size="large"
                    loading={loading}
                    disabled={loading}
                  >
                    {loading ? 'Sending...' : 'Send Reset Link'}
                  </Button>

                  <div style={{ textAlign: 'center' }}>
                    <Text variant="body" style={{ color: 'var(--muted-foreground)' }}>
                      Remember your password?{' '}
                      <Link
