                        style={{
                          color: 'var(--primary)',
                          textDecoration: 'none',
                        }}
                      >
                        Sign in
                      </Link>
                    </Text>
                  </div>
                </div>
              </form>
            )}
          </div>
        </Card>
      </Container>
    </div>
  );
}

