  { id: 'settings', label: 'Settings', path: '/dashboard/settings', icon: <SettingsIcon /> },
];

export const SideDrawer: React.FC<SideDrawerProps> = ({ open, onClose }) => {
  const { user, signOut } = useAuth();
  const { data: roles } = (trpc as any).user.roles.useQuery(undefined, { staleTime: 60_000 });
  const pathname = usePathname();
  const router = useRouter();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const haptic = useHaptic();

  // Swipe-to-close gesture for mobile
  const swipeHandlers = useSwipeGesture({
    onSwipeLeft: () => {
      if (isMobile && onClose) {
        haptic.light();
        onClose();
      }
    },
  });

  const handleSignOut = async () => {
    try {
      await signOut();
      router.push('/');
      if (onClose) onClose();
    } catch (error) {
      console.error('Sign out error:', error);
    }
