const SLIDES = [
  { type: "browser" as const, url: "app.devflow.io/dashboard", label: "Pipeline Dashboard", alt: "Pipeline dashboard" },
  { type: "os-window" as const, title: "Devflow — VS Code Extension", label: "IDE Integration", alt: "IDE integration" },
