   ═══════════════════════════════════════════════════════════ */

const S = {
  bg: "#0D0D0D",
  panel: "#161616",
  card: "#1A1A1A",
  cardHover: "#1F1F1F",
  border: "#262626",
  borderSubtle: "#1E1E1E",
  text: "#E5E5E5",
  textMuted: "#888888",
  textDim: "#555555",
