  violet: "#8B5CF6",
  gold: "#EAB308",
};

/* ─── Micro-helpers ─── */

function Pill({ color, children }: { color: string; children: React.ReactNode }) {
  return (
    <span
      style={{
        fontSize: 9,
        fontWeight: 600,
        padding: "2px 6px",
        borderRadius: 4,
        background: `${color}18`,
        color,
        letterSpacing: "0.02em",
        whiteSpace: "nowrap",
      }}
    >
      {children}
    </span>
  );
}

function StatusDot({ color }: { color: string }) {
  return (
    <span
      style={{
        width: 6,
        height: 6,
        borderRadius: "50%",
        background: color,
        display: "inline-block",
        flexShrink: 0,
      }}
    />
  );
}

function BarSegment({ width, color }: { width: string; color: string }) {
  return (
    <div
      style={{
        height: 4,
        borderRadius: 2,
        background: color,
        width,
        flexShrink: 0,
      }}
    />
  );
}

function Skeleton({ w, h = 8, r = 3 }: { w: string | number; h?: number; r?: number }) {
  return (
    <div
      style={{
        width: typeof w === "number" ? w : w,
        height: h,
        borderRadius: r,
        background: S.border,
        flexShrink: 0,
      }}
    />
  );
}

