'use client';

import React, { useMemo } from 'react';
import ReactECharts from 'echarts-for-react';
import { Card, Heading, Text } from '@/design-system';
import { designTokens } from '@/lib/theme/tokens';

interface DealStat {
  deal_id: string;
  deal_title: string;
  totalSellerRevenue: number;
  totalRevenue: number;
  completedPurchases: number;
}

interface RevenueDistributionChartProps {
  dealStats?: DealStat[];
  loading?: boolean;
}

export const RevenueDistributionChart: React.FC<RevenueDistributionChartProps> = ({
  dealStats = [],
  loading = false,
}) => {
  const chartData = useMemo(() => {
    if (!dealStats || dealStats.length === 0) {
      return [];
    }

    return dealStats
      .filter((deal) => deal.totalSellerRevenue > 0)
      .map((deal) => ({
        name: deal.deal_title.length > 30 
          ? `${deal.deal_title.substring(0, 30)}...` 
          : deal.deal_title,
        value: typeof deal.totalSellerRevenue === 'string'
          ? parseFloat(deal.totalSellerRevenue)
          : deal.totalSellerRevenue,
        fullName: deal.deal_title,
        purchases: deal.completedPurchases,
      }))
      .sort((a, b) => b.value - a.value);
  }, [dealStats]);

  const totalRevenue = useMemo(() => {
    return chartData.reduce((sum, item) => sum + item.value, 0);
  }, [chartData]);

  const option = useMemo(() => {
    if (chartData.length === 0) {
      return null;
    }

    // Generate colors for chart slices
    const colors = [
      designTokens.colors.action.primary,
      designTokens.colors.success.main,
      '#F59E0B', // warning color
      '#8B5CF6', // purple
      '#EC4899', // pink
      '#06B6D4', // cyan
    ];

    return {
      backgroundColor: 'transparent',
      textStyle: {
        color: designTokens.colors.text.primary,
        fontFamily: designTokens.typography.fontFamily.primary,
      },
      tooltip: {
        trigger: 'item',
        backgroundColor: designTokens.colors.surface.elevated,
        borderColor: designTokens.colors.surface.border,
        textStyle: {
          color: designTokens.colors.text.primary,
        },
        formatter: (params: any) => {
          const data = params.data;
          const percentage = ((data.value / totalRevenue) * 100).toFixed(1);
          return `
            <div style="padding: 8px;">
              <div style="margin-bottom: 4px;"><strong>${data.fullName}</strong></div>
              <div>Revenue: <strong>$${data.value.toFixed(2)}</strong></div>
              <div>Percentage: <strong>${percentage}%</strong></div>
              <div>Purchases: <strong>${data.purchases}</strong></div>
            </div>
          `;
        },
      },
      legend: {
        orient: 'vertical',
        right: 10,
        top: 'center',
        textStyle: {
          color: designTokens.colors.text.secondary,
          fontSize: 12,
        },
        formatter: (name: string) => {
          const item = chartData.find((d) => d.name === name);
          if (!item) return name;
          const percentage = ((item.value / totalRevenue) * 100).toFixed(1);
          return `${name} (${percentage}%)`;
        },
      },
      series: [
        {
          name: 'Revenue Distribution',
          type: 'pie',
          radius: ['40%', '70%'], // Donut chart
          center: ['40%', '50%'],
          avoidLabelOverlap: false,
          itemStyle: {
            borderRadius: 4,
            borderColor: designTokens.colors.surface.base,
            borderWidth: 2,
          },
          label: {
            show: true,
            formatter: (params: any) => {
              const percentage = ((params.value / totalRevenue) * 100).toFixed(1);
              return `${percentage}%`;
            },
            color: designTokens.colors.text.primary,
            fontSize: 12,
          },
          emphasis: {
            label: {
              show: true,
              fontSize: 14,
              fontWeight: 'bold',
            },
            itemStyle: {
              shadowBlur: 10,
              shadowOffsetX: 0,
              shadowColor: 'rgba(0, 0, 0, 0.5)',
            },
          },
          data: chartData.map((item, index) => ({
            ...item,
            itemStyle: {
              color: colors[index % colors.length],
            },
          })),
        },
      ],
    };
  }, [chartData, totalRevenue]);

  if (loading) {
    return (
      <Card variant="elevated">
        <div style={{ padding: designTokens.spacing.xl, minHeight: '400px' }}>
          <Text variant="body" style={{ color: designTokens.colors.text.secondary }}>
            Loading chart data...
          </Text>
        </div>
      </Card>
    );
  }

  if (!dealStats || dealStats.length === 0 || chartData.length === 0) {
    return (
      <Card variant="elevated">
        <div style={{ padding: designTokens.spacing.xl, minHeight: '400px' }}>
          <Heading level={3} variant="headline" style={{ marginBottom: designTokens.spacing.md }}>
            Revenue Distribution
          </Heading>
          <Text variant="body" style={{ color: designTokens.colors.text.secondary }}>
            No revenue data available to display.
          </Text>
        </div>
      </Card>
    );
  }

  return (
    <Card variant="elevated">
      <div style={{ padding: designTokens.spacing.xl }}>
        <Heading level={3} variant="headline" style={{ marginBottom: designTokens.spacing.lg }}>
          Revenue Distribution by Deal
        </Heading>
        <ReactECharts
          option={option}
          style={{ height: '400px', width: '100%' }}
          opts={{ renderer: 'svg' }}
        />
      </div>
    </Card>
  );
};

'use client';

import React, { useMemo } from 'react';
import ReactECharts from 'echarts-for-react';
import { Card, Heading, Text } from '@/design-system';
import { designTokens } from '@/lib/theme/tokens';

interface PurchaseData {
  created_at: string;
  seller_revenue: string | number;
  status: string;
}

interface RevenueLineChartProps {
  purchases?: PurchaseData[];
  loading?: boolean;
  startDate?: string | null;
  endDate?: string | null;
}

export const RevenueLineChart: React.FC<RevenueLineChartProps> = ({
  purchases = [],
  loading = false,
  startDate,
  endDate,
}) => {
  const chartData = useMemo(() => {
    if (!purchases || purchases.length === 0) {
      return { dates: [], revenues: [], cumulative: [] };
    }

    // Filter by date range and status
    const filtered = purchases.filter((p) => {
      if (p.status !== 'completed') return false;
      if (!startDate && !endDate) return true;

      const purchaseDate = new Date(p.created_at);
      if (startDate && purchaseDate < new Date(startDate)) return false;
      if (endDate && purchaseDate > new Date(endDate)) return false;
      return true;
    });

    // Group by date and calculate cumulative revenue
    const dateMap = new Map<string, number>();

    filtered.forEach((p) => {
      const date = new Date(p.created_at).toISOString().split('T')[0];
      const revenue = typeof p.seller_revenue === 'string' 
        ? parseFloat(p.seller_revenue) 
        : p.seller_revenue;

      dateMap.set(date, (dateMap.get(date) || 0) + revenue);
    });

    // Sort dates and calculate cumulative
    const sortedDates = Array.from(dateMap.keys()).sort();
    const revenues: number[] = [];
    const cumulative: number[] = [];
    let runningTotal = 0;

    sortedDates.forEach((date) => {
      const dailyRevenue = dateMap.get(date) || 0;
      runningTotal += dailyRevenue;
      revenues.push(dailyRevenue);
      cumulative.push(runningTotal);
    });

    return {
      dates: sortedDates,
      revenues,
      cumulative,
    };
  }, [purchases, startDate, endDate]);

  const option = useMemo(() => {
    if (chartData.dates.length === 0) {
      return null;
    }

    return {
      backgroundColor: 'transparent',
      textStyle: {
        color: designTokens.colors.text.primary,
        fontFamily: designTokens.typography.fontFamily.primary,
      },
      tooltip: {
        trigger: 'axis',
        backgroundColor: designTokens.colors.surface.elevated,
        borderColor: designTokens.colors.surface.border,
        textStyle: {
          color: designTokens.colors.text.primary,
        },
        formatter: (params: any) => {
          const param = params[0];
          return `
            <div style="padding: 8px;">
              <div style="margin-bottom: 4px;"><strong>${param.axisValue}</strong></div>
              <div>Daily Revenue: <strong>$${param.value.toFixed(2)}</strong></div>
              <div>Cumulative: <strong>$${chartData.cumulative[param.dataIndex].toFixed(2)}</strong></div>
            </div>
          `;
        },
      },
      grid: {
        left: '3%',
        right: '4%',
        bottom: '3%',
        containLabel: true,
      },
      xAxis: {
        type: 'category',
        boundaryGap: false,
        data: chartData.dates,
        axisLine: {
          lineStyle: {
            color: designTokens.colors.surface.border,
          },
        },
        axisLabel: {
          color: designTokens.colors.text.secondary,
        },
      },
      yAxis: {
        type: 'value',
        axisLine: {
          lineStyle: {
            color: designTokens.colors.surface.border,
          },
        },
        axisLabel: {
          color: designTokens.colors.text.secondary,
          formatter: (value: number) => `$${value.toFixed(0)}`,
        },
        splitLine: {
          lineStyle: {
            color: designTokens.colors.surface.border,
            opacity: 0.3,
          },
        },
      },
      series: [
        {
          name: 'Daily Revenue',
          type: 'line',
          data: chartData.revenues,
          smooth: true,
          lineStyle: {
            color: designTokens.colors.action.primary,
            width: 2,
          },
          itemStyle: {
            color: designTokens.colors.action.primary,
          },
          areaStyle: {
            color: {
              type: 'linear',
              x: 0,
              y: 0,
              x2: 0,
              y2: 1,
              colorStops: [
                {
                  offset: 0,
                  color: `${designTokens.colors.action.primary}40`,
                },
                {
                  offset: 1,
                  color: `${designTokens.colors.action.primary}00`,
                },
              ],
            },
          },
        },
        {
          name: 'Cumulative Revenue',
          type: 'line',
          data: chartData.cumulative,
          smooth: true,
          lineStyle: {
            color: designTokens.colors.success.main,
            width: 2,
            type: 'dashed',
          },
          itemStyle: {
            color: designTokens.colors.success.main,
          },
        },
      ],
      legend: {
        data: ['Daily Revenue', 'Cumulative Revenue'],
        textStyle: {
          color: designTokens.colors.text.secondary,
        },
        top: 10,
      },
    };
  }, [chartData]);

  if (loading) {
    return (
      <Card variant="elevated">
        <div style={{ padding: designTokens.spacing.xl, minHeight: '400px' }}>
          <Text variant="body" style={{ color: designTokens.colors.text.secondary }}>
            Loading chart data...
          </Text>
        </div>
      </Card>
    );
  }

  if (!purchases || purchases.length === 0 || chartData.dates.length === 0) {
    return (
      <Card variant="elevated">
        <div style={{ padding: designTokens.spacing.xl, minHeight: '400px' }}>
          <Heading level={3} variant="headline" style={{ marginBottom: designTokens.spacing.md }}>
            Revenue Over Time
          </Heading>
          <Text variant="body" style={{ color: designTokens.colors.text.secondary }}>
            No purchase data available for the selected date range.
          </Text>
        </div>
      </Card>
    );
  }

  return (
    <Card variant="elevated">
      <div style={{ padding: designTokens.spacing.xl }}>
        <Heading level={3} variant="headline" style={{ marginBottom: designTokens.spacing.lg }}>
          Revenue Over Time
        </Heading>
        <ReactECharts
          option={option}
          style={{ height: '400px', width: '100%' }}
          opts={{ renderer: 'svg' }}
        />
      </div>
    </Card>
  );
};

'use client';

import { createContext, useContext, useEffect, useState } from 'react';
import { User } from '@supabase/supabase-js';
import { createClient } from '@/lib/supabase/client';
import { trpc } from '@/lib/trpc/client';

interface AuthContextType {
  user: User | null;
  loading: boolean;
  signIn: (email: string, password: string) => Promise<void>;
  signUp: (email: string, password: string) => Promise<void>;
  signOut: () => Promise<void>;
  resetPassword: (email: string) => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const supabase = createClient();
  const onboardMutation = (trpc as any).user.onboard.useMutation();

  useEffect(() => {
    // Get initial session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null);
      setLoading(false);
    });

    // Listen for auth changes
    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
    });

    return () => subscription.unsubscribe();
  }, []);

  const signIn = async (email: string, password: string) => {
    if (!email || !password) {
      throw new Error('Email and password are required');
    }

    const trimmedEmail = email.trim();

    const { data, error } = await supabase.auth.signInWithPassword({
      email: trimmedEmail,
      password,
    });

    if (error) {
      console.error('Sign in error:', {
        message: error.message,
        status: error.status,
        name: error.name,
        email: trimmedEmail,
      });

      // Provide more helpful error messages
      if (error.message === 'Invalid login credentials') {
        throw new Error(
          'Invalid email or password. Please check:\n' +
          '1. The email address is correct\n' +
          '2. The password is correct\n' +
          '3. The account exists in Supabase Auth\n' +
          '4. The account email is confirmed (check Supabase Dashboard)\n' +
          '5. Try resetting the password if needed'
        );
      }

      throw error;
    }
  };

  const signUp = async (email: string, password: string) => {
    const { data, error } = await supabase.auth.signUp({
      email: email.trim(),
      password,
      options: {
        emailRedirectTo: `${typeof window !== 'undefined' ? window.location.origin : ''}/auth/confirm`,
      },
    });
    if (error) throw error;

    // After successful signup, call onboarding to create tenant and user record
    // This is the alternative to the database trigger approach
    // Note: Only call if user was created (data.user exists)
    if (data.user) {
      try {
        await onboardMutation.mutateAsync();
      } catch (onboardError) {
        // Log error but don't fail signup - user can still log in
        // The database trigger approach is more reliable for this reason
        console.error('Failed to onboard user after signup:', onboardError);
        // Optionally, you could throw the error here to fail signup
        // throw onboardError;
      }
    }
  };

  const signOut = async () => {
    const { error } = await supabase.auth.signOut();
    if (error) throw error;
  };

  const resetPassword = async (email: string) => {
    if (!email) {
      throw new Error('Email is required');
    }

    const { error } = await supabase.auth.resetPasswordForEmail(email.trim(), {
      redirectTo: `${window.location.origin}/auth/confirm`,
    });

    if (error) {
      console.error('Password reset error:', error);
      throw error;
    }
  };

  return (
    <AuthContext.Provider value={{ user, loading, signIn, signUp, signOut, resetPassword }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

/**
 * Button Component (Atom)
 * Pill primary, rounded secondary/ghost; generous padding; no elevation/ripple
 */

'use client';

import React, { useState } from 'react';
import { animations } from '../../tokens';

const PILL_RADIUS = '9999px';
const ROUNDED_RADIUS = '16px';
const PADDING_X = 'clamp(24px, 28px, 32px)';
const PADDING_Y = 'clamp(12px, 14px, 16px)';
const BUTTON_GAP = '8px';

export interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost' | 'destructive' | 'premium';
  size?: 'small' | 'medium' | 'large';
  children: React.ReactNode;
  loading?: boolean;
  iconOnly?: boolean;
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({
  variant = 'primary',
  size = 'medium',
  children,
  loading = false,
  iconOnly = false,
  fullWidth = false,
  disabled,
  className = '',
  ...props
}) => {
  const isDisabled = disabled || loading;
  const [isHovered, setIsHovered] = useState(false);

  const isPill = variant === 'primary' || variant === 'destructive' || variant === 'premium';

  const sizeConfig = {
    small: { height: 'clamp(32px, 40px, 44px)', fontSize: 'clamp(13px, 14px, 15px)' },
    medium: { height: 'clamp(40px, 44px, 48px)', fontSize: 'clamp(14px, 15px, 16px)' },
    large: { height: 'clamp(48px, 52px, 56px)', fontSize: 'clamp(16px, 17px, 17px)' },
  };

  const config = sizeConfig[size];

  const getVariantStyles = (): React.CSSProperties => {
    const base: React.CSSProperties = {
      borderRadius: isPill ? PILL_RADIUS : ROUNDED_RADIUS,
      border: 'none',
      fontFamily: 'var(--font-body), -apple-system, BlinkMacSystemFont, sans-serif',
      fontWeight: 500,
      cursor: isDisabled ? 'not-allowed' : 'pointer',
      transition: `all ${animations.duration.standard}ms ${animations.easing.easeInOut}`,
      display: 'inline-flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: BUTTON_GAP,
      width: fullWidth ? '100%' : 'auto',
      minWidth: iconOnly ? config.height : 'auto',
      opacity: isDisabled ? 0.5 : 1,
      boxShadow: 'none',
      paddingLeft: iconOnly ? 0 : PADDING_X,
      paddingRight: iconOnly ? 0 : PADDING_X,
      paddingTop: PADDING_Y,
      paddingBottom: PADDING_Y,
    };

    let variantStyles: React.CSSProperties = { ...base };

    switch (variant) {
      case 'primary':
        variantStyles = {
          ...base,
          background: 'var(--primary)',
          color: 'var(--primary-foreground)',
        };
        if (isHovered && !isDisabled) {
          variantStyles.background = '#5A9AFF';
          variantStyles.boxShadow = '0 2px 8px rgba(0, 0, 0, 0.12)';
        }
        break;
      case 'secondary':
        variantStyles = {
          ...base,
          background: 'var(--card)',
          color: 'var(--foreground)',
          border: '1px solid var(--border)',
        };
        if (isHovered && !isDisabled) {
          variantStyles.background = 'var(--popover)';
          variantStyles.boxShadow = '0 2px 8px rgba(0, 0, 0, 0.08)';
        }
        break;
      case 'outline':
        variantStyles = {
          ...base,
          background: isHovered && !isDisabled ? 'var(--surface-glow)' : 'transparent',
          color: 'var(--muted-foreground)',
          border: `1px solid ${isHovered && !isDisabled ? 'var(--primary)' : 'var(--border)'}`,
        };
        if (isHovered && !isDisabled) {
          variantStyles.color = 'var(--foreground)';
          variantStyles.boxShadow = '0 1px 4px rgba(0, 0, 0, 0.08)';
        }
        break;
      case 'ghost':
        variantStyles = {
          ...base,
          background: isHovered && !isDisabled ? 'var(--card)' : 'transparent',
          color: 'var(--muted-foreground)',
        };
        if (isHovered && !isDisabled) variantStyles.color = 'var(--foreground)';
        break;
      case 'destructive':
        variantStyles = {
          ...base,
          background: 'var(--destructive)',
          color: 'var(--destructive-foreground)',
        };
        if (isHovered && !isDisabled) {
          variantStyles.background = '#DC2626';
          variantStyles.boxShadow = '0 2px 8px rgba(239, 68, 68, 0.25)';
        }
        break;
      case 'premium':
        variantStyles = {
          ...base,
          background: 'var(--primary)',
          color: 'var(--primary-foreground)',
        };
        if (isHovered && !isDisabled) {
          variantStyles.background = '#5A9AFF';
          variantStyles.boxShadow = '0 2px 8px rgba(0, 0, 0, 0.12)';
        }
        break;
      default:
        variantStyles = base;
    }

    return variantStyles;
  };

  const baseStyle: React.CSSProperties = {
    ...getVariantStyles(),
    height: config.height,
    fontSize: config.fontSize,
  };

  const style: React.CSSProperties = {
    ...baseStyle,
    ...(props.style || {}),
  };

  const { style: _, ...restProps } = props;

  return (
    <button
      type="button"
      disabled={isDisabled}
      className={className}
      style={style}
      onMouseEnter={() => !isDisabled && setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onMouseDown={(e) => {
        if (!isDisabled) e.currentTarget.style.transform = 'scale(0.98)';
      }}
      onMouseUp={(e) => {
        if (!isDisabled) e.currentTarget.style.transform = '';
      }}
      onTouchStart={(e) => {
        if (!isDisabled) e.currentTarget.style.transform = 'scale(0.98)';
      }}
      onTouchEnd={(e) => {
        e.currentTarget.style.transform = '';
      }}
      {...restProps}
    >
      {loading ? (
        <>
          <span style={{ display: 'inline-block', width: '16px', height: '16px', border: '2px solid currentColor', borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin 0.6s linear infinite' }} />
          {children}
        </>
      ) : (
        children
      )}
    </button>
  );
};

