/**
 * Gesture Utilities
 * iOS-style gestures: swipe, pull-to-refresh
 */

'use client';

import { RefObject, useEffect } from 'react';

export interface SwipeGestureOptions {
  onSwipeLeft?: () => void;
  onSwipeRight?: () => void;
  onSwipeUp?: () => void;
  onSwipeDown?: () => void;
  threshold?: number; // Minimum distance in pixels
  velocityThreshold?: number; // Minimum velocity
}

export interface PullToRefreshOptions {
  onRefresh: () => Promise<void> | void;
  threshold?: number; // Pull distance to trigger refresh
  enabled?: boolean;
}

/**
 * Swipe gesture handler
 */
export const useSwipeGesture = (
  ref: RefObject<HTMLElement>,
  options: SwipeGestureOptions
): void => {

  const {
    onSwipeLeft,
    onSwipeRight,
    onSwipeUp,
    onSwipeDown,
    threshold = 50,
    velocityThreshold = 0.3,
  } = options;

  let startX = 0;
  let startY = 0;
  let startTime = 0;
  let isTracking = false;

  const handleTouchStart = (e: TouchEvent) => {
    const touch = e.touches[0];
    startX = touch.clientX;
    startY = touch.clientY;
    startTime = Date.now();
    isTracking = true;
  };

  const handleTouchEnd = (e: TouchEvent) => {
    if (!isTracking) return;

    const touch = e.changedTouches[0];
    const deltaX = touch.clientX - startX;
    const deltaY = touch.clientY - startY;
    const deltaTime = Date.now() - startTime;
    const distance = Math.sqrt(deltaX * deltaX + deltaY * deltaY);
    const velocity = distance / deltaTime;

    // Check if gesture meets threshold
    if (distance < threshold || velocity < velocityThreshold) {
      isTracking = false;
      return;
    }

    // Determine swipe direction
    const absX = Math.abs(deltaX);
    const absY = Math.abs(deltaY);

    if (absX > absY) {
      // Horizontal swipe
      if (deltaX > 0 && onSwipeRight) {
        onSwipeRight();
      } else if (deltaX < 0 && onSwipeLeft) {
        onSwipeLeft();
      }
    } else {
      // Vertical swipe
      if (deltaY > 0 && onSwipeDown) {
        onSwipeDown();
      } else if (deltaY < 0 && onSwipeUp) {
        onSwipeUp();
      }
    }

    isTracking = false;
  };

  useEffect(() => {
    const element = ref.current;
    if (!element) return;

    element.addEventListener('touchstart', handleTouchStart, { passive: true });
    element.addEventListener('touchend', handleTouchEnd, { passive: true });

    return () => {
      element.removeEventListener('touchstart', handleTouchStart);
      element.removeEventListener('touchend', handleTouchEnd);
    };
  }, [ref]);
};

/**
 * Pull-to-refresh handler
 */
export const usePullToRefresh = (
  ref: RefObject<HTMLElement>,
  options: PullToRefreshOptions
): void => {

  const {
    onRefresh,
    threshold = 80,
    enabled = true,
  } = options;

  let startY = 0;
  let currentY = 0;
  let isPulling = false;
  let isRefreshing = false;

  const handleTouchStart = (e: TouchEvent) => {
    if (!enabled || isRefreshing) return;

    const element = ref.current;
    if (!element) return;

    // Only trigger if at the top of the scrollable area
    if (element.scrollTop > 0) return;

    const touch = e.touches[0];
    startY = touch.clientY;
    isPulling = true;
  };

  const handleTouchMove = (e: TouchEvent) => {
    if (!isPulling || isRefreshing) return;

    const touch = e.touches[0];
    currentY = touch.clientY;
    const deltaY = currentY - startY;

    if (deltaY > 0) {
      // Prevent default scrolling while pulling
      e.preventDefault();

      // Visual feedback (could be enhanced with a loading indicator)
      const element = ref.current;
      if (element) {
        const pullDistance = Math.min(deltaY, threshold * 1.5);
        element.style.transform = `translateY(${pullDistance}px)`;
      }
    }
  };

  const handleTouchEnd = async () => {
    if (!isPulling) return;

    const element = ref.current;
    if (element) {
      const deltaY = currentY - startY;

      // Reset transform
      element.style.transform = 'translateY(0)';
      element.style.transition = 'transform 300ms cubic-bezier(0.4, 0, 0.2, 1)';

      // Trigger refresh if threshold met
      if (deltaY >= threshold && !isRefreshing) {
        isRefreshing = true;
        try {
          await onRefresh();
        } finally {
          isRefreshing = false;
        }
      }

      // Reset transition after animation
      setTimeout(() => {
        if (element) {
          element.style.transition = '';
        }
      }, 300);
    }

    isPulling = false;
  };

  useEffect(() => {
    const element = ref.current;
    if (!element || !enabled) return;

    element.addEventListener('touchstart', handleTouchStart, { passive: false });
    element.addEventListener('touchmove', handleTouchMove, { passive: false });
    element.addEventListener('touchend', handleTouchEnd, { passive: true });

    return () => {
      element.removeEventListener('touchstart', handleTouchStart);
      element.removeEventListener('touchmove', handleTouchMove);
      element.removeEventListener('touchend', handleTouchEnd);
    };
  }, [ref, enabled]);
};

import { createTRPCReact } from '@trpc/react-query';

/**
 * tRPC React Client
 * 
 * This creates a type-safe React hook for calling tRPC procedures.
 * The AppRouter type will be inferred from the backend router.
 * 
 * Usage:
 *   const { data } = trpc.tenant.get.useQuery();
 *   const mutation = trpc.app.create.useMutation();
 */

// For now, we use 'any' as the router type since backend is JavaScript
// In production, you'd generate this type from the backend or convert backend to TypeScript
export const trpc = createTRPCReact<any>();

'use client';

import { useState } from 'react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { httpBatchLink } from '@trpc/client';
import { trpc } from './client';
import { createClient } from '@/lib/supabase/client';
import { queryCacheConfig, retryConfig } from './cache-config';

/**
 * tRPC Provider
 * 
 * Wraps the app with tRPC client and React Query provider.
 * Automatically includes authentication token in requests.
 */
export function TRPCProvider({ children }: { children: React.ReactNode }) {
  const [queryClient] = useState(
    () =>
      new QueryClient({
        defaultOptions: {
          queries: {
            ...queryCacheConfig.default,
            ...retryConfig,
            // Background refetching for better UX
            refetchInterval: false,
            refetchIntervalInBackground: false,
          },
          mutations: {
            ...retryConfig,
            // Optimistic updates enabled by default
            onError: (error) => {
              console.error('Mutation error:', error);
            },
          },
        },
      })
  );

  const supabase = createClient();

  const [trpcClient] = useState(() =>
    (trpc as any).createClient({
      links: [
        httpBatchLink({
          url: `${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'}/trpc`,
          async headers() {
            // Get the current session and include the access token
            const {
              data: { session },
            } = await supabase.auth.getSession();

            return {
              authorization: session?.access_token
                ? `Bearer ${session.access_token}`
                : '',
            };
          },
        }),
      ],
    })
  );

  const TRPCProvider = (trpc as any).Provider;

  return (
    <TRPCProvider client={trpcClient} queryClient={queryClient}>
      <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
    </TRPCProvider>
  );
}

/**
 * Debounce utility function
 * Delays function execution until after a specified time period has passed
 */

export function debounce<T extends (...args: any[]) => any>(
  func: T,
  wait: number
): (...args: Parameters<T>) => void {
  let timeout: NodeJS.Timeout | null = null;

  return function executedFunction(...args: Parameters<T>) {
    const later = () => {
      timeout = null;
      func(...args);
    };

    if (timeout) {
      clearTimeout(timeout);
    }
    timeout = setTimeout(later, wait);
  };
}

/**
 * React hook for debounced values
 */
import { useState, useEffect } from 'react';

export function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState<T>(value);

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => {
      clearTimeout(handler);
    };
  }, [value, delay]);

  return debouncedValue;
}

