(() => {
  const defaultBaseUrl = (() => {
    try {
      const current = document.currentScript?.src ? new URL(document.currentScript.src) : new URL(window.location.href);
      return `${current.protocol}//${current.host}`;
    } catch {
      return window.location.origin;
    }
  })();

  function openPopup(url, name, features) {
    const popup = window.open(url, name, features);
    if (!popup) {
      throw new Error('Popup blocked. Please allow popups for this site.');
    }
    return popup;
  }

  function buildPopupUrl(baseUrl, appId, embedToken) {
    const url = new URL('/embed/auth', baseUrl);
    url.searchParams.set('appId', appId);
    url.searchParams.set('embedToken', embedToken);
    url.searchParams.set('pwaOrigin', window.location.origin);
    return url.toString();
  }

  async function authenticate({ appId, embedToken, baseUrl = defaultBaseUrl, popupFeatures = 'width=480,height=720' }) {
    if (!appId || !embedToken) {
      throw new Error('appId and embedToken are required');
    }

    const popupUrl = buildPopupUrl(baseUrl, appId, embedToken);
    const popup = openPopup(popupUrl, 'marketplace-embed-auth', popupFeatures);

    return new Promise((resolve, reject) => {
      const timeout = setTimeout(() => {
        cleanup();
        reject(new Error('Authentication timed out'));
      }, 2 * 60 * 1000);

      function cleanup() {
        clearTimeout(timeout);
        window.removeEventListener('message', onMessage);
      }

      function onMessage(event) {
        if (event.origin !== new URL(baseUrl).origin) {
          return;
        }
        const data = event.data || {};
        if (data.type !== 'EMBED_AUTH_RESULT') return;
        cleanup();
        resolve({ token: data.token, expiresAt: data.expiresAt, appId: data.appId });
      }

      window.addEventListener('message', onMessage);
    });
  }

  window.MarketplaceEmbed = {
    authenticate,
  };
})();

/**
 * Service Worker
 * PWA offline support, caching, and push notifications
 * Enhanced with multiple caching strategies
 */

const CACHE_VERSION = 'v2';
const STATIC_CACHE = `deathtosaas-static-${CACHE_VERSION}`;
const DYNAMIC_CACHE = `deathtosaas-dynamic-${CACHE_VERSION}`;
const API_CACHE = `deathtosaas-api-${CACHE_VERSION}`;
const OFFLINE_PAGE = '/offline';

// Static assets to cache on install (cache-first strategy)
const STATIC_ASSETS = [
  '/',
  '/offline',
  '/manifest.json',
  '/icons/icon-192.png',
  '/icons/icon-512.png',
];

// Cache duration in milliseconds
const CACHE_DURATIONS = {
  static: 7 * 24 * 60 * 60 * 1000, // 7 days
  dynamic: 24 * 60 * 60 * 1000, // 1 day
  api: 5 * 60 * 1000, // 5 minutes
};

// Install event - cache static assets
self.addEventListener('install', (event) => {
  console.log('[Service Worker] Installing...');
  event.waitUntil(
    caches.open(STATIC_CACHE).then((cache) => {
      console.log('[Service Worker] Caching static assets');
      return cache.addAll(STATIC_ASSETS).catch((err) => {
        console.warn('[Service Worker] Failed to cache some static assets:', err);
      });
    })
  );
  self.skipWaiting();
});

// Activate event - clean up old caches
self.addEventListener('activate', (event) => {
  console.log('[Service Worker] Activating...');
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames
          .filter((name) => 
            name !== STATIC_CACHE && 
            name !== DYNAMIC_CACHE && 
            name !== API_CACHE
          )
          .map((name) => {
            console.log('[Service Worker] Deleting old cache:', name);
            return caches.delete(name);
          })
      );
    }).then(() => self.clients.claim())
  );
});

/**
 * Cache-first strategy: Check cache first, fallback to network
 * Best for: Static assets (images, fonts, CSS, JS)
 */
async function cacheFirst(request, cacheName) {
  const cache = await caches.open(cacheName);
  const cachedResponse = await cache.match(request);

  if (cachedResponse) {
    return cachedResponse;
  }

  try {
    const networkResponse = await fetch(request);
    if (networkResponse && networkResponse.status === 200) {
      cache.put(request, networkResponse.clone());
    }
    return networkResponse;
  } catch (error) {
    // If offline and navigating, return offline page
    if (request.mode === 'navigate') {
      const offlinePage = await cache.match(OFFLINE_PAGE);
      if (offlinePage) return offlinePage;
    }
    throw error;
  }
}

/**
 * Network-first strategy: Try network first, fallback to cache
 * Best for: API calls, dynamic content
 */
async function networkFirst(request, cacheName) {
  const cache = await caches.open(cacheName);

  try {
    const networkResponse = await fetch(request);
    if (networkResponse && networkResponse.status === 200) {
      cache.put(request, networkResponse.clone());
    }
    return networkResponse;
  } catch (error) {
    const cachedResponse = await cache.match(request);
    if (cachedResponse) {
      return cachedResponse;
    }
    throw error;
  }
}

/**
 * Stale-while-revalidate strategy: Return cache immediately, update in background
 * Best for: Frequently accessed data that can tolerate slight staleness
 */
async function staleWhileRevalidate(request, cacheName) {
  const cache = await caches.open(cacheName);
  const cachedResponse = await cache.match(request);

  // Fetch fresh data in background
  const fetchPromise = fetch(request).then((networkResponse) => {
    if (networkResponse && networkResponse.status === 200) {
      cache.put(request, networkResponse.clone());
    }
    return networkResponse;
  }).catch(() => {
    // Ignore network errors in background fetch
  });

  // Return cached version immediately if available
  if (cachedResponse) {
    return cachedResponse;
  }

  // If no cache, wait for network
  return fetchPromise;
}

// Fetch event - route requests to appropriate caching strategy
self.addEventListener('fetch', (event) => {
  const { request } = event;
  const url = new URL(request.url);

  // Skip cross-origin requests (except API calls to our backend)
  if (url.origin !== location.origin && !url.pathname.startsWith('/api/')) {
    return;
  }

  // Skip non-GET requests
  if (request.method !== 'GET') {
    return;
  }

  // Route to appropriate caching strategy
  if (url.pathname.startsWith('/api/') || url.pathname.startsWith('/trpc/')) {
    // API calls: Network-first with cache fallback
    event.respondWith(networkFirst(request, API_CACHE));
  } else if (
    url.pathname.match(/\.(jpg|jpeg|png|gif|webp|svg|ico|woff|woff2|ttf|eot)$/i) ||
    url.pathname.startsWith('/_next/static/') ||
    url.pathname.startsWith('/_next/image')
  ) {
    // Static assets: Cache-first strategy
    event.respondWith(cacheFirst(request, STATIC_CACHE));
  } else if (url.pathname.startsWith('/dashboard/') || url.pathname.startsWith('/marketplace/')) {
    // Dynamic pages: Stale-while-revalidate for better UX
    event.respondWith(staleWhileRevalidate(request, DYNAMIC_CACHE));
  } else {
    // Default: Network-first
    event.respondWith(networkFirst(request, DYNAMIC_CACHE));
  }
});

// Push notification event
self.addEventListener('push', (event) => {
  console.log('[Service Worker] Push notification received');

  const data = event.data ? event.data.json() : {};
  const title = data.title || 'DeathToSaaS';
  const options = {
    body: data.body || 'You have a new notification',
    icon: '/icons/icon-192.png',
    badge: '/icons/icon-192.png',
    tag: data.tag || 'default',
    data: data.data || {},
    requireInteraction: data.requireInteraction || false,
    actions: data.actions || [],
  };

  event.waitUntil(
    self.registration.showNotification(title, options)
  );
});

// Notification click event
self.addEventListener('notificationclick', (event) => {
  console.log('[Service Worker] Notification clicked');
  event.notification.close();

  const urlToOpen = event.notification.data?.url || '/';

  event.waitUntil(
    clients.matchAll({ type: 'window', includeUncontrolled: true }).then((clientList) => {
      // Check if there's already a window open
      for (let i = 0; i < clientList.length; i++) {
        const client = clientList[i];
        if (client.url === urlToOpen && 'focus' in client) {
          return client.focus();
        }
      }
      // Open a new window
      if (clients.openWindow) {
        return clients.openWindow(urlToOpen);
      }
    })
  );
});

// Background sync event
self.addEventListener('sync', (event) => {
  console.log('[Service Worker] Background sync:', event.tag);

  if (event.tag === 'background-sync') {
    event.waitUntil(
      // Perform background sync operations
      Promise.resolve()
    );
  }
});

// Message event - for communication with the app
self.addEventListener('message', (event) => {
  console.log('[Service Worker] Message received:', event.data);

  if (event.data && event.data.type === 'SKIP_WAITING') {
    self.skipWaiting();
  }
});
